export interface Session {
  id: string;
  title: string;
  category: 'Economics' | 'Engineering' | 'Career' | 'Design' | 'Science';
  timeLabel: string;
  status: 'LIVE' | 'UPCOMING' | 'NOW';
  mentorName: string;
