              placeholder="Scholastic Background & Achievements..." 
              className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm h-36 resize-none focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]"
