              placeholder="Password" 
              required
              className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5] transition-all" 
            />

            {authMode === 'signup' && (
