                  <div onClick={() => setModalType('apply')} className="border-2 border-dashed border-gray-100 rounded-2xl p-8 flex flex-col items-center justify-center text-center group cursor-pointer hover:border-[#7FB5B5] transition-all bg-gray-50/30 hover:bg-white min-h-[300px] animate-in fade-in zoom-in-95 duration-700">
                    <div className="w-14 h-14 bg-white shadow-sm rounded-full flex items-center justify-center mb-6 group-hover:bg-[#7FB5B5]/10 transition-colors duration-500">
                      <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-gray-300 group-hover:text-[#7FB5B5] transition-colors duration-500"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
                    </div>
                    <h4 className="font-bold text-[#1A2238] mb-3 text-lg">Propose a Session</h4>
                    <p className="text-xs text-gray-400 max-w-[220px] leading-relaxed font-light">Possess a unique perspective? Apply to share your insight with the community.</p>
                  </div>
                </div>
              </div>
            </section>

            <section id="philosophy" className="py-24 md:py-32 max-w-5xl mx-auto px-6">
              <div className="text-center mb-24">
                <span className="text-[#C5A059] font-bold tracking-[0.2em] uppercase text-[10px] mb-4 block">The Mission</span>
                <h2 className="text-4xl md:text-5xl font-playfair font-bold text-[#1A2238]">The Scholastic Trajectory</h2>
