              <div className="grid md:grid-cols-3 gap-16 relative" id="fellows">
                <div className="hidden md:block absolute top-12 left-0 w-full h-px bg-gray-100 -z-10"></div>
                {[
                  { id: '01', title: 'Community Scholarship', status: 'In Motion', desc: 'Transforming elite institutional knowledge into decentralized community assets.' },
                  { id: '02', title: 'Applied Advocacy', status: 'Expanding', desc: 'Direct mentorship pipelines connecting industry luminaries with emerging talent.' },
                  { id: '03', title: 'Global Academic Void', status: 'Vision 2025', desc: 'Constructing the infrastructure for the first student-owned global university.' }
                ].map(item => (
                  <div key={item.id} className="relative group">
                    <div className="w-12 h-12 bg-[#1A2238] text-white font-bold flex items-center justify-center rounded-full mb-10 shadow-xl transition-all group-hover:bg-[#C5A059] group-hover:scale-110">{item.id}</div>
                    <div>
                      <h4 className="font-bold text-xl mb-3 text-[#1A2238]">{item.title}</h4>
                      <div className="inline-block px-2 py-0.5 rounded bg-[#FDFBF7] border border-gray-100 text-[9px] font-bold uppercase mb-5 tracking-widest text-[#7FB5B5]">{item.status}</div>
                      <p className="text-gray-500 text-sm leading-relaxed font-light">{item.desc}</p>
                    </div>
