            </button>
          </div>
          <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 blur-3xl rounded-full"></div>
        </section>
      </main>

      {/* Detail Session Modal */}
      <Modal 
        isOpen={modalType === 'session' && !!selectedSession} 
        onClose={() => setModalType(null)} 
