                </div>

                <div className="bg-[#1A2238] p-8 rounded-3xl text-white flex flex-col md:flex-row items-center justify-between gap-6 shadow-xl">
                  <div className="text-center md:text-left">
                    <h3 className="text-xl font-playfair font-bold mb-2">Ready to enter the discussion?</h3>
                    <p className="text-gray-400 text-sm font-light">Join the live session using the unique portal provided for this masterclass.</p>
