                  <div className="flex items-center gap-4 mb-6">
                    <img src={selectedSession.avatarUrl} alt={selectedSession.mentorName} className="w-16 h-16 rounded-full object-cover grayscale" />
                    <div>
                      <p className="font-bold text-[#1A2238]">{selectedSession.mentorName}</p>
                      <p className="text-[10px] text-gray-400 uppercase tracking-tighter">{selectedSession.mentorInst}</p>
                    </div>
                  </div>
                  <p className="text-sm text-gray-500 leading-relaxed font-light">{selectedSession.mentorBio}</p>
                </div>

                {selectedSession.relatedSessionIds && (
                  <div>
                    <h4 className="text-[10px] font-bold uppercase tracking-[0.2em] text-gray-400 mb-6">Related Sessions</h4>
                    <div className="space-y-4">
                      {selectedSession.relatedSessionIds.map(id => {
                        const related = sessions.find(s => s.id === id);
                        if (!related) return null;
                        return (
                          <div key={id} onClick={() => handleSessionSelect(related)} className="p-4 bg-white border border-gray-50 rounded-2xl hover:border-[#7FB5B5] cursor-pointer transition-all hover:shadow-sm group">
                            <p className="text-[9px] uppercase font-bold text-[#7FB5B5] mb-1">{related.category}</p>
                            <p className="text-sm font-bold text-[#1A2238] group-hover:text-[#7FB5B5] transition-colors line-clamp-1">{related.title}</p>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </Modal>

      <Modal isOpen={modalType === 'auth'} onClose={() => setModalType(null)} title={authMode === 'login' ? "Scholastic Login" : "Join the Collective"} size="sm">
        <form onSubmit={handleAuth} className="space-y-4">
          {authMode === 'signup' && <input name="name" type="text" placeholder="Full Name" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]" />}
          <input name="email" type="email" placeholder="Institutional Email" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]" />
          <input name="password" type="password" placeholder="Password" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]" />
          <button type="submit" className="w-full bg-[#1A2238] text-white py-4 rounded-xl font-bold text-sm tracking-widest uppercase hover:bg-[#7FB5B5] transition-all">
            {authMode === 'login' ? 'Enter Network' : 'Request Access'}
          </button>
        </form>
        <p className="text-center text-xs text-gray-400 mt-6">
          {authMode === 'login' ? "New here?" : "Already a member?"}{" "}
          <button onClick={() => setAuthMode(authMode === 'login' ? 'signup' : 'login')} className="text-[#1A2238] font-bold hover:underline">
            {authMode === 'login' ? "Create an account" : "Log in to existing"}
          </button>
        </p>
      </Modal>

      <Modal isOpen={modalType === 'apply'} onClose={() => setModalType(null)} title="Scholarly Dossier">
        <form onSubmit={handleApplyDossier} className="space-y-6">
          <p className="text-xs text-gray-500 italic">Please detail your area of specialization for review by our academic board.</p>
          <input value={applyData.expertise} onChange={(e) => setApplyData({...applyData, expertise: e.target.value})} required type="text" placeholder="Primary Domain of Expertise" className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]" />
          <textarea value={applyData.background} onChange={(e) => setApplyData({...applyData, background: e.target.value})} placeholder="Scholastic Background & Achievements..." className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm h-36 resize-none focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]"></textarea>
          <button type="submit" className="w-full bg-[#C5A059] text-white py-4 rounded-xl font-bold text-sm tracking-widest uppercase hover:bg-[#1A2238] transition-all shadow-lg">Submit Dossier</button>
        </form>
      </Modal>

      <Modal isOpen={modalType === 'admin'} onClose={() => setModalType(null)} title="System Administration" size="lg">
        <div className="space-y-12">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] uppercase font-bold text-gray-400 block mb-2">Total Scholars</span>
              <span className="text-3xl font-bold text-[#1A2238]">{userList.length}</span>
            </div>
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] uppercase font-bold text-gray-400 block mb-2">Academic Reviews</span>
              <span className="text-3xl font-bold text-[#C5A059]">{reviews.length}</span>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex items-center gap-3">
              <div className="w-1.5 h-6 bg-[#7FB5B5] rounded-full"></div>
              <h3 className="text-lg font-playfair font-bold text-[#1A2238]">Academic Logistics: Session Links</h3>
            </div>
            <div className="space-y-4">
              {sessions.map((session) => (
                <div key={session.id} className="bg-white border border-gray-100 p-5 rounded-2xl hover:shadow-md transition-shadow group">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] font-bold uppercase tracking-widest text-[#7FB5B5] bg-[#7FB5B5]/10 px-2 py-0.5 rounded-full">{session.category}</span>
                        <h4 className="text-sm font-bold text-[#1A2238]">{session.title}</h4>
                      </div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-tighter">{session.mentorName} · {session.mentorInst}</p>
                    </div>

                    <div className="flex flex-1 items-center gap-2">
                      <input 
                        type="url" 
                        defaultValue={session.zoomLink || ''}
                        placeholder="https://zoom.us/j/..."
                        onBlur={(e) => handleAdminUpdateZoomLink(session.id, e.target.value)}
                        className="flex-1 bg-gray-50 border border-gray-100 rounded-xl px-3 py-2 text-xs focus:ring-1 focus:ring-[#7FB5B5] outline-none transition-all"
                      />
                      <button 
                        className="text-[9px] font-bold uppercase tracking-widest text-white bg-[#1A2238] px-3 py-2 rounded-xl hover:bg-[#7FB5B5] transition-colors"
                        onClick={(e) => {
                          const input = (e.currentTarget.previousElementSibling as HTMLInputElement);
                          handleAdminUpdateZoomLink(session.id, input.value);
                          alert("Link updated successfully.");
                        }}
                      >
                        Update
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex items-center gap-3">
              <div className="w-1.5 h-6 bg-[#C5A059] rounded-full"></div>
              <h3 className="text-lg font-playfair font-bold text-[#1A2238]">Scholastic Registry</h3>
            </div>
            <div className="max-h-[300px] overflow-y-auto space-y-2 pr-2">
              {userList.length > 0 ? userList.map((u, i) => (
                <div key={i} className="flex justify-between items-center p-4 bg-gray-50 border border-gray-100 rounded-2xl text-xs">
                  <div>
                    <p className="font-bold text-[#1A2238]">{u.name || u.email}</p>
                    <p className="text-[10px] text-gray-400 uppercase tracking-tighter">{u.email}</p>
                  </div>
                  <span className="text-gray-300 font-mono text-[9px]">{u.date}</span>
                </div>
              )) : (
                <p className="text-xs text-gray-400 text-center py-8 italic font-light">No scholars registered in the current node.</p>
              )}
            </div>
          </div>
        </div>
      </Modal>

      <Concierge />
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { SessionCard } from './components/SessionCard';
import { Concierge } from './components/Concierge';
import { INITIAL_SESSIONS } from './constants';
import { Session, Review } from './types';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, size = 'md' }) => {
  if (!isOpen) return null;

  const sizeClasses = {
    sm: 'max-w-md',
    md: 'max-w-2xl',
    lg: 'max-w-4xl',
    xl: 'max-w-6xl'
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#1A2238]/60 backdrop-blur-sm" onClick={onClose}></div>
      <div className={`relative bg-white w-full ${sizeClasses[size]} rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300 max-h-[90vh] flex flex-col`}>
        <div className="p-8 pb-4 flex justify-between items-center sticky top-0 bg-white z-10">
          <h2 className="text-2xl font-playfair font-bold text-[#1A2238]">{title}</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-2 hover:bg-gray-50 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>
        <div className="overflow-y-auto flex-1 p-8 pt-0">
          {children}
        </div>
      </div>
    </div>
  );
};

function App() {
  const [sessions, setSessions] = useState<Session[]>(INITIAL_SESSIONS);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [filter, setFilter] = useState<string>('All');
  const [modalType, setModalType] = useState<'auth' | 'apply' | 'admin' | 'session' | null>(null);
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [userList, setUserList] = useState<any[]>([]);
  const [activeView, setActiveView] = useState<'landing' | 'community'>('landing');

  // Review Form state
  const [reviewRating, setReviewRating] = useState(5);
  const [reviewComment, setReviewComment] = useState('');

  // Form states for join/apply
  const [applyData, setApplyData] = useState({ 
    name: '', 
    email: '', 
    expertise: '', 
    background: '' 
  });

  useEffect(() => {
    const savedUsers = localStorage.getItem('lumina_users');
    if (savedUsers) setUserList(JSON.parse(savedUsers));

    const activeSession = localStorage.getItem('lumina_active_user');
    if (activeSession) {
      const user = JSON.parse(activeSession);
      setCurrentUser(user);
      // Pre-fill apply data if user is logged in
      setApplyData(prev => ({
        ...prev,
        name: user.name || '',
        email: user.email || ''
      }));
    }

    const savedReviews = localStorage.getItem('lumina_reviews');
    if (savedReviews) setReviews(JSON.parse(savedReviews));

    const savedSessions = localStorage.getItem('lumina_sessions_registry');
    if (savedSessions) {
      setSessions(JSON.parse(savedSessions));
    }
  }, []);

  const categories = ['All', 'Economics', 'Engineering', 'Career', 'Design'];
  const filteredSessions = filter === 'All' ? sessions : sessions.filter(s => s.category === filter);

  const sendEmailNotification = (subject: string, body: string) => {
    const recipient = 'siraajjuneja@hotmail.com';
    const mailtoUrl = `mailto:${recipient}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    window.location.href = mailtoUrl;
  };

  const scrollToSection = (id: string) => {
    if (activeView !== 'landing') {
      setActiveView('landing');
      setTimeout(() => {
        const element = document.getElementById(id);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      const element = document.getElementById(id);
      if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const handleSessionSelect = (session: Session) => {
    setSelectedSession(session);
    setModalType('session');
    setReviewComment('');
    setReviewRating(5);
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const email = (e.target as any).email.value;
    const name = authMode === 'signup' ? (e.target as any).name?.value : 'Returning Scholar';

    const newUser = { email, name, date: new Date().toLocaleDateString() };
    const updatedList = [...userList, newUser];

    setUserList(updatedList);
    localStorage.setItem('lumina_users', JSON.stringify(updatedList));
    localStorage.setItem('lumina_active_user', JSON.stringify(newUser));
    setCurrentUser(newUser);

    // Sync apply data pre-fill
    setApplyData(prev => ({
      ...prev,
      name: newUser.name,
      email: newUser.email
    }));

    if (authMode === 'signup') {
      const subject = `Lumina Registration: ${name}`;
      const body = `A new user has registered for Lumina.\n\nName: ${name}\nEmail: ${email}\nDate: ${newUser.date}`;
      sendEmailNotification(subject, body);
    }

    setModalType(null);
  };

  const handleLogout = () => {
    localStorage.removeItem('lumina_active_user');
    setCurrentUser(null);
    setApplyData({ name: '', email: '', expertise: '', background: '' });
  };

  const handleApplyDossier = (e: React.FormEvent) => {
    e.preventDefault();

    const { name, email, expertise, background } = applyData;

    // Check if user is logged in first
    if (!currentUser) {
      alert("Please log in or create an account before submitting your scholarly dossier.");
      setAuthMode('signup');
      setModalType('auth');
      return;
    }

    // Persist expertise to user profile if needed
    const updatedUser = { ...currentUser, name, email, expertise };
    setCurrentUser(updatedUser);
    localStorage.setItem('lumina_active_user', JSON.stringify(updatedUser));
    const updatedList = userList.map(u => u.email === currentUser.email ? updatedUser : u);
    setUserList(updatedList);
    localStorage.setItem('lumina_users', JSON.stringify(updatedList));

    // Construct Formal Dossier Email
    const subject = `Fellowship Scholarly Dossier: ${name}`;
    const body = `SCHOLARLY FELLOWSHIP APPLICATION\n------------------------------\n\nNAME: ${name}\nEMAIL: ${email}\nDOMAIN OF EXPERTISE: ${expertise}\n\nACADEMIC BACKGROUND & ACHIEVEMENTS:\n${background}\n\n------------------------------\nSUBMITTED VIA LUMINA PEER-LEARNING PORTAL\nTIMESTAMP: ${new Date().toLocaleString()}`;

    sendEmailNotification(subject, body);

    alert("Your scholarly dossier has been generated. Please send the triggered email to complete the submission process.");
    setModalType(null);
  };

  const handleSubmitReview = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) {
      setAuthMode('login');
      setModalType('auth');
      return;
    }
    if (!selectedSession) return;

    const newReview: Review = {
      id: Math.random().toString(36).substr(2, 9),
      sessionId: selectedSession.id,
      userName: currentUser.name,
      rating: reviewRating,
      comment: reviewComment,
      date: new Date().toLocaleDateString()
    };

    const updatedReviews = [...reviews, newReview];
    setReviews(updatedReviews);
    localStorage.setItem('lumina_reviews', JSON.stringify(updatedReviews));
    setReviewComment('');
    setReviewRating(5);
  };

  const handleAdminUpdateZoomLink = (sessionId: string, newLink: string) => {
    const updatedSessions = sessions.map(s => 
      s.id === sessionId ? { ...s, zoomLink: newLink } : s
    );
    setSessions(updatedSessions);
    localStorage.setItem('lumina_sessions_registry', JSON.stringify(updatedSessions));

    if (selectedSession && selectedSession.id === sessionId) {
      setSelectedSession({ ...selectedSession, zoomLink: newLink });
    }
  };

  const getSessionReviews = (sessionId: string) => reviews.filter(r => r.sessionId === sessionId);

  return (
    <div className="min-h-screen flex flex-col relative">
      <nav className="flex justify-between items-center px-6 md:px-12 py-6 sticky top-0 bg-[#FDFBF7]/90 backdrop-blur-md z-40 border-b border-gray-50">
        <div className="text-2xl font-bold tracking-tighter font-playfair hover:text-[#7FB5B5] cursor-pointer transition-colors" onClick={() => { setActiveView('landing'); window.scrollTo({top: 0, behavior: 'smooth'}); }}>
          LUMINA
        </div>
        <div className="hidden md:flex space-x-10 text-xs uppercase tracking-widest font-semibold text-gray-500">
          <button onClick={() => scrollToSection('workshops')} className="hover:text-[#1A2238] transition">Sessions</button>
          <button onClick={() => scrollToSection('fellows')} className="hover:text-[#1A2238] transition">Scholars</button>
          <button onClick={() => scrollToSection('philosophy')} className="hover:text-[#1A2238] transition">Our Vision</button>
