                    <div className="w-14 h-14 bg-white shadow-sm rounded-full flex items-center justify-center mb-6 group-hover:bg-[#7FB5B5]/10 transition-colors duration-500">
                      <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-gray-300 group-hover:text-[#7FB5B5] transition-colors duration-500"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
