              <label className="text-[10px] uppercase tracking-widest font-bold text-gray-400 px-1">Full Name *</label>
              <input 
                value={applyData.name} 
                onChange={(e) => setApplyData({...applyData, name: e.target.value})} 
                required 
                type="text" 
                placeholder="Scholastic Name" 
                className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]" 
              />
