            <div className="space-y-1.5">
              <label className="text-[10px] uppercase tracking-widest font-bold text-gray-400 px-1">Institutional Email *</label>
              <input 
                value={applyData.email} 
                onChange={(e) => setApplyData({...applyData, email: e.target.value})} 
                required 
                type="email" 
                placeholder="university@email.edu" 
                className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]" 
              />
