          <div className="space-y-1.5">
            <label className="text-[10px] uppercase tracking-widest font-bold text-gray-400 px-1">Research Background & Achievements *</label>
            <textarea 
              value={applyData.background} 
              onChange={(e) => setApplyData({...applyData, background: e.target.value})} 
              required
              placeholder="Detail your academic trajectory and unique insights..." 
              className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm h-32 resize-none focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5]"
            ></textarea>
          </div>

          <button 
            type="submit" 
            className="w-full bg-[#1A2238] text-white py-4 rounded-xl font-bold text-sm tracking-widest uppercase hover:bg-[#C5A059] transition-all shadow-lg active:scale-95"
          >
