                      <div className="space-y-2">
                        <label className="text-[10px] uppercase tracking-widest font-bold text-[#1A2238]/40 px-1">Knowledge Domain</label>
                        <select 
                          name="category"
                          defaultValue={session.category}
                          className="w-full bg-gray-50/50 border border-gray-100 rounded-2xl px-6 py-4 text-sm outline-none cursor-pointer appearance-none hover:bg-white transition-colors"
                        >
                          {categories.filter(c => c !== 'All').map(c => <option key={c} value={c}>{c}</option>)}
