                      </div>
                    </div>

                    <div className="space-y-6">
                      <div className="space-y-2">
                        <label className="text-[10px] uppercase tracking-widest font-bold text-[#1A2238]/40 px-1">Short Narrative (Card View)</label>
                        <textarea 
                          name="description"
                          defaultValue={session.description}
