                  {/* Commit Action Bar */}
                  <div className="mt-10 pt-8 border-t border-gray-50 flex flex-col md:flex-row justify-between items-center gap-6 relative z-10">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-gray-50 rounded-lg">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#94A3B8" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="8.5" cy="7" r="4"></circle><polyline points="17 11 19 13 23 9"></polyline></svg>
                      </div>
                      <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Moderator: {session.mentorName}</span>
                    </div>

                    <div className="flex items-center gap-3">
                      {confirmingSessionId === session.id ? (
