                          <button 
                            onClick={() => setConfirmingSessionId(null)}
                            className="px-6 py-2.5 rounded-xl text-[10px] font-bold uppercase tracking-widest text-gray-500 hover:bg-gray-100 transition-all"
                          >
                            Discard
                          </button>
                          <button 
                            onClick={() => handleAdminCommitSession(session.id)}
                            className="px-8 py-2.5 rounded-xl bg-[#1A2238] text-white text-[10px] font-bold uppercase tracking-widest hover:bg-[#7FB5B5] shadow-lg transition-all"
