            <div className="bg-[#1A2238] p-8 rounded-[2rem] border border-[#1A2238] shadow-xl text-white">
              <span className="text-[10px] uppercase font-bold text-[#7FB5B5] block mb-2 tracking-widest">Global Scholars</span>
              <span className="text-4xl font-bold font-playfair">{userList.length}</span>
            </div>
            <div className="bg-gray-50 p-8 rounded-[2rem] border border-gray-100 shadow-sm">
              <span className="text-[10px] uppercase font-bold text-gray-400 block mb-2 tracking-widest">Masterclass Catalog</span>
              <span className="text-4xl font-bold text-[#1A2238] font-playfair">{sessions.length}</span>
