                <h4 className="text-lg font-playfair font-bold text-[#1A2238] mb-8 flex items-center gap-2">
                  <div className="w-2 h-2 bg-[#7FB5B5] rounded-full animate-ping"></div>
                  New Masterclass Specification
                </h4>
                <div className="grid md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[10px] uppercase tracking-widest font-bold text-[#1A2238]/60 px-1">Session Title *</label>
                      <input name="title" required type="text" className="w-full bg-white border border-gray-100 rounded-2xl px-6 py-4 text-sm focus:ring-2 focus:ring-[#7FB5B5]/20 outline-none" placeholder="e.g. Advanced Game Theory" />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] uppercase tracking-widest font-bold text-[#1A2238]/60 px-1">Category *</label>
                        <select name="category" className="w-full bg-white border border-gray-100 rounded-2xl px-6 py-4 text-sm outline-none">
