                        <textarea name="longDescription" defaultValue={session.longDescription} className="w-full bg-gray-50/50 border border-gray-100 rounded-2xl px-6 py-4 text-sm h-40 resize-none outline-none focus:ring-2 focus:ring-[#7FB5B5]/20" />
                      </div>
