                    {isAddingNew ? 'Cancel Creation' : 'Create New Masterclass'}
                  </button>
                </div>

                {/* Create Session Form and Existing Session List (Previously built) */}
                {isAddingNew && (
                  <div ref={newSessionFormRef} className="bg-gray-50 p-10 rounded-[2.5rem] animate-scale space-y-6">
                    <input name="title" placeholder="Masterclass Title" className="w-full p-4 rounded-2xl border outline-none" />
                    <div className="grid grid-cols-2 gap-4">
                      <select name="category" className="p-4 rounded-2xl border outline-none">
                        {categories.filter(c => c !== 'All').map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                      <input name="timeLabel" placeholder="Time (e.g. LIVE @ 6 PM)" className="p-4 rounded-2xl border outline-none" />
                    </div>
                    <input name="zoomLink" placeholder="Zoom Link" className="w-full p-4 rounded-2xl border outline-none font-mono text-[#C5A059]" />
                    <textarea name="description" placeholder="Brief Description" className="w-full p-4 rounded-2xl border outline-none h-24" />
                    <button onClick={handleAdminCreateSession} className="w-full bg-[#1A2238] text-white py-4 rounded-2xl font-bold text-xs uppercase tracking-widest">Register Session</button>
                  </div>
                )}

                <div className="space-y-8">
                  {sessions.map(session => (
                    <div key={session.id} ref={el => adminFormRefs.current[session.id] = el} className="p-8 border border-gray-100 rounded-[2.5rem] bg-white group relative">
                      <div className="flex justify-between mb-6">
                        <input name="title" defaultValue={session.title} className="text-lg font-bold bg-transparent outline-none focus:border-b border-[#7FB5B5] w-full mr-12" />
                        <button onClick={() => handleAdminDeleteSession(session.id)} className="text-red-300 hover:text-red-500"><svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg></button>
                      </div>
                      <div className="grid md:grid-cols-2 gap-8 mb-6">
                        <div className="space-y-4">
                          <input name="zoomLink" defaultValue={session.zoomLink} placeholder="Zoom Link" className="w-full p-3 rounded-xl border text-xs font-mono text-[#C5A059] bg-[#C5A059]/5" />
                          <select name="category" defaultValue={session.category} className="w-full p-3 rounded-xl border text-xs outline-none">
                            {categories.filter(c => c !== 'All').map(c => <option key={c} value={c}>{c}</option>)}
                          </select>
                        </div>
                        <textarea name="description" defaultValue={session.description} className="w-full p-3 rounded-xl border text-xs h-full" />
                      </div>
                      <button onClick={() => handleAdminCommitSession(session.id)} className="w-full bg-gray-50 hover:bg-[#1A2238] hover:text-white py-3 rounded-2xl text-[10px] font-bold uppercase transition-all">Save Curriculum Updates</button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </Modal>

      {/* Standard Auth Modal */}
      <Modal isOpen={modalType === 'auth'} onClose={() => setModalType(null)} title={authMode === 'login' ? "Scholastic Login" : "Join the Collective"} size="sm">
        <form onSubmit={handleAuth} className="space-y-4 animate-in opacity-0">
          {authMode === 'signup' && <input name="name" type="text" placeholder="Full Name" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5] outline-none" />}
          <input name="email" type="email" placeholder="Institutional Email" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5] outline-none" />
          <input name="password" type="password" placeholder="Secure Password" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-[#7FB5B5]/20 focus:border-[#7FB5B5] outline-none" />
          <button type="submit" className="w-full bg-[#1A2238] text-white py-4 rounded-xl font-bold text-sm tracking-widest uppercase hover:bg-[#7FB5B5] transition-all shadow-lg active:scale-95">
            {authMode === 'login' ? 'Enter Network' : 'Request Scholarly Access'}
          </button>
        </form>
      </Modal>

      {/* Fellowship Application Modal */}
      <Modal isOpen={modalType === 'apply'} onClose={() => setModalType(null)} title="Fellowship Scholarly Dossier">
        <form onSubmit={handleApplyDossier} className="space-y-6 animate-in opacity-0">
          <p className="text-[10px] text-gray-400 italic mb-4">Your application will be directly reviewed by the Fellowship Board on the Global Admin Dashboard.</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input value={applyData.name} onChange={(e) => setApplyData({...applyData, name: e.target.value})} required type="text" placeholder="Full Scholar Name *" className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-[#7FB5B5]/20 outline-none" />
            <input value={applyData.email} onChange={(e) => setApplyData({...applyData, email: e.target.value})} required type="email" placeholder="Institutional Email *" className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-[#7FB5B5]/20 outline-none" />
          </div>
          <input value={applyData.expertise} onChange={(e) => setApplyData({...applyData, expertise: e.target.value})} required type="text" placeholder="Academic Domain of Expertise *" className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-[#7FB5B5]/20 outline-none" />
          <textarea value={applyData.background} onChange={(e) => setApplyData({...applyData, background: e.target.value})} required placeholder="Research Background, Fellowships, and Contributions..." className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm h-44 resize-none focus:ring-2 focus:ring-[#7FB5B5]/20 outline-none"></textarea>
          <button type="submit" className="w-full bg-[#C5A059] text-white py-5 rounded-2xl font-bold text-sm tracking-widest uppercase hover:bg-[#1A2238] transition-all shadow-xl active:scale-95">
            Submit Dossier for Evaluation
          </button>
        </form>
      </Modal>

      <Concierge />
    </div>
  );
}

export default App;

import React from 'react';
import { Session, Review } from '../types';

interface SessionCardProps {
  session: Session;
  onJoin?: (id: string) => void;
  onSelect?: (session: Session) => void;
  isExpertiseMatch?: boolean;
  reviews: Review[];
}

export const SessionCard: React.FC<SessionCardProps> = ({ session, onJoin, onSelect, isExpertiseMatch, reviews }) => {
  const isNow = session.status === 'NOW' || session.status === 'LIVE';
  const hasLink = !!session.zoomLink && session.zoomLink.trim() !== '';

  const categoryColor = session.category === 'Career' ? 'text-[#C5A059] bg-[#C5A059]/10' : 'text-[#7FB5B5] bg-[#7FB5B5]/10';

  const averageRating = reviews.length > 0 
    ? (reviews.reduce((acc, r) => acc + r.rating, 0) / reviews.length).toFixed(1)
    : null;

  const handleJoinClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (hasLink) {
      window.open(session.zoomLink, '_blank', 'noopener,noreferrer');
      onJoin?.(session.id);
    }
  };

  return (
    <div 
      onClick={() => onSelect?.(session)}
      className="glass-card p-6 rounded-[2.5rem] shadow-xl hover:shadow-[0_0_50px_-12px_rgba(127,181,181,0.2)] hover:scale-[1.03] hover:-translate-y-2 transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] group flex flex-col h-full animate-in opacity-0 cursor-pointer relative overflow-hidden"
    >
      {/* Glow highlight on hover */}
      <div className="absolute inset-0 bg-gradient-to-tr from-[#7FB5B5]/0 to-[#7FB5B5]/5 opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none"></div>

      <div className="flex justify-between items-start mb-6 relative z-10">
        <div className="flex flex-wrap items-center gap-2">
          <span className={`${categoryColor} text-[10px] px-3 py-1 rounded-full font-bold uppercase tracking-wider transition-all duration-500 group-hover:bg-white/10`}>
            {session.category}
          </span>
          {isExpertiseMatch && (
            <div className="flex items-center gap-1.5 bg-[#C5A059]/10 border border-[#C5A059]/20 px-2 py-1 rounded-full">
              <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="#C5A059" stroke="#C5A059" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon></svg>
              <span className="text-[8px] font-bold text-[#C5A059] uppercase tracking-tighter">Match</span>
            </div>
          )}
        </div>
        <span className={`text-[10px] font-mono font-bold tracking-tight ${isNow ? 'text-red-400 animate-pulse' : 'text-gray-500'}`}>
          {session.timeLabel}
        </span>
      </div>

      <div className="relative z-10">
        <h3 className="text-xl mb-3 font-bold font-playfair leading-tight text-white group-hover:text-[#7FB5B5] transition-colors duration-300">
          {session.title}
        </h3>

        <p className="text-sm text-gray-400 mb-6 line-clamp-2 font-light leading-relaxed group-hover:text-gray-300 transition-colors duration-500">
          {session.description}
        </p>

        {hasLink && (
          <div className="flex items-center gap-2 mb-6 bg-white/5 p-2.5 rounded-2xl border border-white/5 group-hover:border-[#7FB5B5]/30 transition-all duration-500">
            <div className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse shadow-[0_0_8px_rgba(74,222,128,0.5)]"></div>
            <span className="text-[9px] font-mono text-gray-500 truncate max-w-[200px]">
              {session.zoomLink}
            </span>
          </div>
        )}
      </div>

      <div className="mt-auto relative z-10">
        <div className="flex items-center gap-3 mb-6">
          <img 
            src={session.avatarUrl} 
            alt={session.mentorName} 
            className="w-10 h-10 rounded-full border border-white/10 object-cover opacity-80 group-hover:opacity-100 transition-all duration-700"
          />
          <div>
            <p className="text-xs font-bold text-gray-200">{session.mentorName}</p>
            <p className="text-[10px] text-gray-500 uppercase tracking-tighter">
              {session.mentorInst}
            </p>
          </div>
        </div>

        <button 
          disabled={!hasLink}
          onClick={handleJoinClick}
          className={`w-full py-4 rounded-2xl text-[10px] uppercase tracking-[0.25em] font-bold transition-all duration-500 transform active:scale-95 flex items-center justify-center gap-2 ${
            isNow 
              ? 'bg-[#7FB5B5] text-[#05070A] shadow-[#7FB5B5]/20 shadow-xl hover:bg-white' 
              : 'border border-white/20 text-white hover:bg-white hover:text-[#05070A] hover:border-white'
          } ${!hasLink ? 'opacity-20 cursor-not-allowed grayscale' : ''}`}
        >
          {hasLink ? (
            <>
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="group-hover:rotate-12 transition-transform duration-500"><path d="M15.6 11.6L22 7v10l-6.4-4.6v-0.8z"/><rect x="2" y="6" width="12" height="12" rx="2"/></svg>
              Join Session
            </>
          ) : (
            'Access Pending'
          )}
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { SessionCard } from './components/SessionCard';
import { Concierge } from './components/Concierge';
import { INITIAL_SESSIONS } from './constants';
import { Session, Review, UserRecord, FellowshipApplication } from './types';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, size = 'md' }) => {
  if (!isOpen) return null;

  const sizeClasses = {
    sm: 'max-w-md',
    md: 'max-w-2xl',
    lg: 'max-w-4xl',
    xl: 'max-w-6xl'
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#05070A]/90 backdrop-blur-md" onClick={onClose}></div>
      <div className={`relative bg-[#0B0F1A] border border-white/5 w-full ${sizeClasses[size]} rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale max-h-[90vh] flex flex-col`}>
        <div className="p-8 pb-4 flex justify-between items-center sticky top-0 bg-[#0B0F1A] z-10 border-b border-white/5">
          <h2 className="text-2xl font-playfair font-bold text-white">{title}</h2>
          <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors p-2 hover:bg-white/5 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>
        <div className="overflow-y-auto flex-1 p-8 pt-6">
          {children}
        </div>
      </div>
    </div>
  );
};

function App() {
  const [sessions, setSessions] = useState<Session[]>(INITIAL_SESSIONS);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [filter, setFilter] = useState<string>('All');
  const [modalType, setModalType] = useState<'auth' | 'apply' | 'admin' | 'session' | null>(null);
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');
  const [currentUser, setCurrentUser] = useState<UserRecord | null>(null);
  const [userList, setUserList] = useState<UserRecord[]>([]);
  const [applications, setApplications] = useState<FellowshipApplication[]>([]);
  const [activeView, setActiveView] = useState<'landing' | 'community'>('landing');
  const [adminTab, setAdminTab] = useState<'insights' | 'scholars' | 'fellowship' | 'curriculum'>('insights');

  // Admin States
  const [confirmingSessionId, setConfirmingSessionId] = useState<string | null>(null);
  const [isAddingNew, setIsAddingNew] = useState(false);
  const adminFormRefs = useRef<{ [key: string]: HTMLDivElement | null }>({});
  const newSessionFormRef = useRef<HTMLDivElement>(null);
  const [editingUser, setEditingUser] = useState<UserRecord | null>(null);

  // Form states for join/apply
  const [applyData, setApplyData] = useState({ 
    name: '', 
    email: '', 
    expertise: '', 
    background: '' 
  });

  useEffect(() => {
    const savedUsers = localStorage.getItem('gyaan_users');
    if (savedUsers) setUserList(JSON.parse(savedUsers));

    const savedApps = localStorage.getItem('gyaan_applications');
    if (savedApps) setApplications(JSON.parse(savedApps));

    const activeSession = localStorage.getItem('gyaan_active_user');
    if (activeSession) {
      const user = JSON.parse(activeSession);
      setCurrentUser(user);
      setApplyData(prev => ({
        ...prev,
        name: user.name || '',
        email: user.email || ''
      }));
    }

    const savedReviews = localStorage.getItem('gyaan_reviews');
    if (savedReviews) setReviews(JSON.parse(savedReviews));

    const savedSessions = localStorage.getItem('gyaan_sessions_registry');
    if (savedSessions) {
      setSessions(JSON.parse(savedSessions));
    }
  }, []);

  const categories = ['All', 'Economics', 'Engineering', 'Career', 'Design', 'Science'];
  const filteredSessions = filter === 'All' ? sessions : sessions.filter(s => s.category === filter);

  const scrollToSection = (id: string) => {
    if (activeView !== 'landing') {
      setActiveView('landing');
      setTimeout(() => {
        const element = document.getElementById(id);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      const element = document.getElementById(id);
      if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const handleSessionSelect = (session: Session) => {
    setSelectedSession(session);
    setModalType('session');
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const email = (e.target as any).email.value;
    const name = authMode === 'signup' ? (e.target as any).name?.value : 'Returning Scholar';

    if (authMode === 'login') {
      const found = userList.find(u => u.email === email);
      if (found) {
        setCurrentUser(found);
        localStorage.setItem('gyaan_active_user', JSON.stringify(found));
        setModalType(null);
        return;
      } else {
        alert("Account not found in the registry.");
        return;
      }
    }

    const newUser: UserRecord = { email, name, date: new Date().toLocaleDateString(), isFellow: false };
    const updatedList = [...userList, newUser];
    setUserList(updatedList);
    localStorage.setItem('gyaan_users', JSON.stringify(updatedList));
    localStorage.setItem('gyaan_active_user', JSON.stringify(newUser));
    setCurrentUser(newUser);
    setModalType(null);
  };

  const handleLogout = () => {
    localStorage.removeItem('gyaan_active_user');
    setCurrentUser(null);
  };

  const handleApplyDossier = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const newApp: FellowshipApplication = {
      id: Math.random().toString(36).substr(2, 9),
      email: applyData.email,
      name: applyData.name,
      expertise: applyData.expertise,
      background: applyData.background,
      status: 'PENDING',
      submittedAt: new Date().toLocaleString()
    };

    const updatedApps = [newApp, ...applications];
    setApplications(updatedApps);
    localStorage.setItem('gyaan_applications', JSON.stringify(updatedApps));
    alert("Dossier submitted for administrative review.");
    setModalType(null);
  };

  // ADMIN DASHBOARD HELPERS
  const adminHandleApplication = (id: string, action: 'APPROVED' | 'REJECTED') => {
    const updatedApps = applications.map(app => {
      if (app.id === id) {
        if (action === 'APPROVED') {
          const updatedUsers = userList.map(u => u.email === app.email ? { ...u, isFellow: true, expertise: app.expertise } : u);
          setUserList(updatedUsers);
          localStorage.setItem('gyaan_users', JSON.stringify(updatedUsers));
        }
        return { ...app, status: action };
      }
      return app;
    });
    setApplications(updatedApps);
    localStorage.setItem('gyaan_applications', JSON.stringify(updatedApps));
  };

  const getSessionReviews = (sessionId: string) => reviews.filter(r => r.sessionId === sessionId);

  return (
    <div className="min-h-screen flex flex-col relative bg-[#05070A] text-gray-300">
      <nav className="flex justify-between items-center px-6 md:px-12 py-6 sticky top-0 bg-[#05070A]/80 backdrop-blur-xl z-40 border-b border-white/5">
        <div className="text-2xl font-bold tracking-tighter font-playfair text-white hover:text-[#7FB5B5] cursor-pointer transition-colors" onClick={() => { setActiveView('landing'); window.scrollTo({top: 0, behavior: 'smooth'}); }}>
          GYAAN FORUM
        </div>
        <div className="hidden md:flex space-x-10 text-[10px] uppercase tracking-[0.2em] font-bold text-gray-500">
          <button onClick={() => scrollToSection('workshops')} className="hover:text-white transition-all">Sessions</button>
          <button onClick={() => { setActiveView('community'); window.scrollTo({top: 0, behavior: 'smooth'}); }} className={`transition-all ${activeView === 'community' ? 'text-white' : 'hover:text-white'}`}>Community</button>
          <button onClick={() => { setModalType('admin'); }} className="text-[#C5A059] hover:text-white transition px-3 py-1 bg-[#C5A059]/10 rounded-full">Admin Panel</button>
        </div>
        <div className="flex items-center gap-4">
          {currentUser ? (
            <div className="flex items-center gap-4">
              {currentUser.isFellow && <span className="bg-[#C5A059]/20 text-[#C5A059] text-[8px] font-bold px-2 py-0.5 rounded-full uppercase border border-[#C5A059]/30">Fellow</span>}
              <span className="text-[10px] uppercase font-bold text-gray-500">{currentUser.name}</span>
              <button onClick={handleLogout} className="text-[10px] uppercase font-bold text-red-500/70 hover:text-red-400 transition">Logout</button>
            </div>
          ) : (
            <button onClick={() => { setAuthMode('signup'); setModalType('auth'); }} className="bg-white text-[#05070A] px-6 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest hover:bg-[#7FB5B5] transition shadow-lg active:scale-95">
              Enter Forum
            </button>
          )}
        </div>
      </nav>

      <main className="flex-1">
        {activeView === 'landing' ? (
          <>
            <section className="relative overflow-hidden hero-gradient pt-24 pb-32">
              <div className="max-w-6xl mx-auto px-6 text-center relative z-10 animate-scale opacity-0">
                <div className="inline-block py-1.5 px-4 mb-8 rounded-full bg-white/5 border border-white/10">
                  <span className="text-[#7FB5B5] font-bold tracking-[0.25em] uppercase text-[9px]">
                    The Collective for Human Potential
                  </span>
                </div>
                <h1 className="text-6xl md:text-9xl mb-10 leading-[0.9] font-playfair font-bold text-white">
                  Knowledge <br className="hidden md:block" />
                  <span className="italic font-normal text-[#C5A059]">unbounded.</span>
                </h1>
                <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto mb-16 leading-relaxed font-light">
                  A peer-to-peer ecosystem designed for high-caliber intellectual exchange. Join masterclasses led by scholars from the world's leading institutions.
                </p>
                <div className="flex flex-col sm:flex-row justify-center gap-6">
                  <button onClick={() => scrollToSection('workshops')} className="bg-white text-[#05070A] px-12 py-5 rounded-2xl font-bold text-xs tracking-widest uppercase hover:scale-105 transition shadow-2xl">
                    Explore Dialogues
                  </button>
                  <button onClick={() => setModalType('apply')} className="border border-white/10 px-12 py-5 rounded-2xl font-bold text-xs tracking-widest uppercase hover:bg-white/5 transition text-white">
                    Apply for Fellowship
                  </button>
                </div>
              </div>
            </section>

            <section id="workshops" className="py-24 md:py-32 bg-[#05070A]">
              <div className="max-w-7xl mx-auto px-6">
                <div className="flex flex-col md:flex-row justify-between items-end mb-20 gap-8">
                  <div className="text-left w-full md:w-auto animate-in opacity-0">
                    <h2 className="text-4xl md:text-6xl font-playfair font-bold mb-4 text-white">Active Curriculum</h2>
                    <p className="text-gray-500 text-lg font-light">Peer-led masterclasses currently in session or upcoming.</p>
                  </div>
                  <div className="flex flex-wrap gap-2 animate-in opacity-0">
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setFilter(cat)} className={`px-6 py-3 rounded-full text-[10px] font-bold uppercase tracking-[0.2em] transition-all duration-300 ${filter === cat ? 'bg-white text-[#05070A] shadow-white/10 shadow-2xl' : 'bg-white/5 text-gray-500 hover:text-white hover:bg-white/10'}`}>
                        {cat}
                      </button>
                    ))}
                  </div>
                </div>

                <div key={filter} className="grid md:grid-cols-2 lg:grid-cols-3 gap-10 stagger-container">
