export default App;

import React, { useState, useRef, useEffect } from 'react';
import { chatWithConcierge } from '../services/geminiService';
import { Message } from '../types';

export const Concierge: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Greetings. I am the Gyaan Forum AI Concierge. How may I assist your scholarly journey today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const response = await chatWithConcierge(messages, userMsg);
      setMessages(prev => [...prev, { role: 'model', text: response || 'Communication link established, but response was empty.' }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: 'An error occurred in the linguistic processing unit.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-8 right-8 bg-white text-[#05070A] p-4 rounded-full shadow-2xl hover:scale-110 hover:bg-[#7FB5B5] transition-all z-[60] group"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path></svg>
      </button>

      <div className={`fixed inset-y-0 right-0 w-full md:w-[450px] bg-[#0B0F1A] shadow-[0_0_100px_-20px_rgba(0,0,0,0.5)] z-[70] transform transition-transform duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] border-l border-white/5 flex flex-col ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-8 border-b border-white/5 flex justify-between items-center bg-[#05070A]/50 backdrop-blur-xl">
          <div>
            <h2 className="font-playfair text-2xl font-bold text-white">Forum Concierge</h2>
            <p className="text-[9px] text-gray-500 uppercase tracking-[0.3em] font-bold">Heuristic Study Assistant</p>
          </div>
          <button onClick={() => setIsOpen(false)} className="text-gray-500 hover:text-white transition-colors p-2 hover:bg-white/5 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-8">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] p-5 rounded-3xl text-sm leading-relaxed ${
                m.role === 'user' 
                  ? 'bg-white text-[#05070A] rounded-tr-none font-medium' 
                  : 'bg-white/5 text-gray-300 border border-white/5 rounded-tl-none font-light'
              }`}>
                {m.text}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-white/5 p-4 rounded-3xl rounded-tl-none border border-white/5 flex gap-1.5 items-center">
                <span className="w-1.5 h-1.5 bg-[#7FB5B5] rounded-full animate-pulse"></span>
                <span className="w-1.5 h-1.5 bg-[#7FB5B5] rounded-full animate-pulse [animation-delay:0.2s]"></span>
                <span className="w-1.5 h-1.5 bg-[#7FB5B5] rounded-full animate-pulse [animation-delay:0.4s]"></span>
              </div>
            </div>
          )}
        </div>

        <div className="p-8 bg-[#05070A]/50 border-t border-white/5">
          <div className="flex gap-3">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Inquire regarding curricula..."
              className="flex-1 bg-white/5 border border-white/5 rounded-2xl px-6 py-4 text-sm text-white focus:outline-none focus:ring-2 focus:ring-[#7FB5B5]/20 focus:bg-white/10 transition-all placeholder:text-gray-600"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading}
              className="bg-white text-[#05070A] px-5 rounded-2xl hover:bg-[#7FB5B5] transition-all disabled:opacity-50 active:scale-95 shadow-xl"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="22" y1="2" x2="11" y2="13"></line><polygon points="22 2 15 22 11 13 2 9 22 2"></polygon></svg>
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

import React from 'react';
import { Session, Review } from '../types';

interface SessionCardProps {
  session: Session;
  onJoin?: (id: string) => void;
  onSelect?: (session: Session) => void;
  isExpertiseMatch?: boolean;
  reviews: Review[];
}

export const SessionCard: React.FC<SessionCardProps> = ({ session, onJoin, onSelect, isExpertiseMatch, reviews }) => {
  const isNow = session.status === 'NOW' || session.status === 'LIVE';
  const hasLink = !!session.zoomLink && session.zoomLink.trim() !== '';

  const categoryColor = session.category === 'Career' ? 'text-[#C5A059] bg-[#C5A059]/10' : 'text-[#7FB5B5] bg-[#7FB5B5]/10';

  const averageRating = reviews.length > 0 
    ? (reviews.reduce((acc, r) => acc + r.rating, 0) / reviews.length).toFixed(1)
    : null;

  const handleJoinClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (hasLink) {
      window.open(session.zoomLink, '_blank', 'noopener,noreferrer');
      onJoin?.(session.id);
    }
  };

  return (
    <div 
      onClick={() => onSelect?.(session)}
      className="glass-card p-6 rounded-[2.5rem] shadow-sm hover:shadow-[0_32px_64px_-16px_rgba(26,34,56,0.12)] hover:scale-[1.025] hover:-translate-y-2.5 transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] group flex flex-col h-full border border-gray-100/50 animate-in opacity-0 cursor-pointer relative overflow-hidden"
    >
      <div className="absolute inset-0 bg-gradient-to-tr from-white/0 via-white/0 to-white/30 opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none"></div>

      <div className="absolute top-0 left-0 w-32 h-32 bg-gradient-to-br from-[#7FB5B5]/5 to-transparent rounded-full -translate-x-16 -translate-y-16 group-hover:scale-[2] transition-transform duration-1000"></div>

      <div className="flex justify-between items-start mb-6 relative z-10">
        <div className="flex flex-wrap items-center gap-2">
          <span className={`${categoryColor} text-[10px] px-3 py-1 rounded-full font-bold uppercase tracking-wider transition-all duration-500 group-hover:bg-white group-hover:shadow-sm`}>
            {session.category}
          </span>
          {isExpertiseMatch && (
            <div className="flex items-center gap-1.5 bg-[#C5A059]/10 border border-[#C5A059]/20 px-2 py-1 rounded-full">
              <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="#C5A059" stroke="#C5A059" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon></svg>
              <span className="text-[8px] font-bold text-[#C5A059] uppercase tracking-tighter">Match</span>
            </div>
          )}
          {averageRating && (
             <div className="flex items-center gap-1 text-[10px] font-bold text-[#C5A059]">
               <span>{averageRating}</span>
               <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="currentColor" stroke="none"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon></svg>
             </div>
          )}
        </div>
        <span className={`text-[10px] font-mono font-bold tracking-tight ${isNow ? 'text-red-500 animate-pulse' : 'text-gray-400'}`}>
          {session.timeLabel}
        </span>
      </div>

      <div className="relative z-10">
        <h3 className="text-xl mb-3 font-bold font-playfair leading-tight text-[#1A2238] group-hover:text-[#7FB5B5] transition-colors duration-300">
          {session.title}
        </h3>

        <p className="text-sm text-gray-500 mb-6 line-clamp-2 font-light leading-relaxed group-hover:text-gray-600 transition-colors duration-500">
          {session.description}
        </p>

        {hasLink && (
          <div className="flex items-center gap-2 mb-6 bg-gray-50/50 p-2.5 rounded-2xl border border-gray-100/50 group-hover:bg-white group-hover:border-[#7FB5B5]/20 transition-all duration-500">
            <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.5)]"></div>
            <span className="text-[9px] font-mono text-gray-400 truncate max-w-[200px]">
              {session.zoomLink}
            </span>
          </div>
        )}
      </div>

      <div className="mt-auto relative z-10">
        <div className="flex items-center gap-3 mb-6">
          <div className="relative overflow-hidden rounded-full">
            <img 
              src={session.avatarUrl} 
              alt={session.mentorName} 
              className="w-12 h-12 rounded-full border-2 border-transparent group-hover:border-[#7FB5B5]/20 object-cover grayscale group-hover:grayscale-0 group-hover:scale-110 transition-all duration-700"
            />
          </div>
          <div className="group-hover:translate-x-1.5 transition-transform duration-500">
            <p className="text-xs font-bold text-[#1A2238]">{session.mentorName}</p>
            <p className="text-[10px] text-gray-400 uppercase tracking-tighter">
              {session.mentorInst}
            </p>
          </div>
        </div>

        <button 
          disabled={!hasLink}
          onClick={handleJoinClick}
          className={`w-full py-4 rounded-2xl text-[10px] uppercase tracking-[0.25em] font-bold transition-all duration-500 transform active:scale-95 flex items-center justify-center gap-2 ${
            isNow 
              ? 'bg-[#1A2238] text-white shadow-[#1A2238]/20 shadow-xl hover:bg-[#7FB5B5] group-hover:-translate-y-1' 
              : 'border border-[#1A2238] text-[#1A2238] hover:bg-[#1A2238] hover:text-white'
          } ${!hasLink ? 'opacity-30 cursor-not-allowed grayscale border-gray-200 text-gray-400' : ''}`}
        >
          {hasLink ? (
            <>
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="group-hover:rotate-12 transition-transform duration-500"><path d="M15.6 11.6L22 7v10l-6.4-4.6v-0.8z"/><rect x="2" y="6" width="12" height="12" rx="2"/></svg>
              Join Masterclass
            </>
          ) : (
            'Link Pending'
          )}
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { SessionCard } from './components/SessionCard';
import { Concierge } from './components/Concierge';
import { INITIAL_SESSIONS } from './constants';
import { Session, Review, UserRecord, FellowshipApplication } from './types';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, size = 'md' }) => {
  if (!isOpen) return null;

  const sizeClasses = {
    sm: 'max-w-md',
    md: 'max-w-2xl',
    lg: 'max-w-4xl',
    xl: 'max-w-6xl'
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#1A2238]/60 backdrop-blur-sm" onClick={onClose}></div>
      <div className={`relative bg-white w-full ${sizeClasses[size]} rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale max-h-[90vh] flex flex-col`}>
        <div className="p-8 pb-4 flex justify-between items-center sticky top-0 bg-white z-10 border-b border-gray-50">
          <h2 className="text-2xl font-playfair font-bold text-[#1A2238]">{title}</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-2 hover:bg-gray-50 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>
        <div className="overflow-y-auto flex-1 p-8 pt-6">
          {children}
        </div>
      </div>
    </div>
  );
};

function App() {
  const [sessions, setSessions] = useState<Session[]>(INITIAL_SESSIONS);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [filter, setFilter] = useState<string>('All');
  const [modalType, setModalType] = useState<'auth' | 'apply' | 'admin' | 'session' | null>(null);
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');
  const [currentUser, setCurrentUser] = useState<UserRecord | null>(null);
  const [userList, setUserList] = useState<UserRecord[]>([]);
  const [applications, setApplications] = useState<FellowshipApplication[]>([]);
  const [activeView, setActiveView] = useState<'landing' | 'community'>('landing');
  const [adminTab, setAdminTab] = useState<'insights' | 'scholars' | 'fellowship' | 'curriculum'>('insights');

  // Admin States
  const [confirmingSessionId, setConfirmingSessionId] = useState<string | null>(null);
  const [isAddingNew, setIsAddingNew] = useState(false);
  const adminFormRefs = useRef<{ [key: string]: HTMLDivElement | null }>({});
  const newSessionFormRef = useRef<HTMLDivElement>(null);
  const [editingUser, setEditingUser] = useState<UserRecord | null>(null);

  // Form states for join/apply
  const [applyData, setApplyData] = useState({ 
    name: '', 
    email: '', 
    expertise: '', 
    background: '' 
  });

  useEffect(() => {
    const savedUsers = localStorage.getItem('gyaan_users');
    if (savedUsers) setUserList(JSON.parse(savedUsers));

    const savedApps = localStorage.getItem('gyaan_applications');
    if (savedApps) setApplications(JSON.parse(savedApps));

    const activeSession = localStorage.getItem('gyaan_active_user');
    if (activeSession) {
      const user = JSON.parse(activeSession);
      setCurrentUser(user);
      setApplyData(prev => ({
        ...prev,
        name: user.name || '',
        email: user.email || ''
      }));
    }

    const savedReviews = localStorage.getItem('gyaan_reviews');
    if (savedReviews) setReviews(JSON.parse(savedReviews));

    const savedSessions = localStorage.getItem('gyaan_sessions_registry');
    if (savedSessions) {
      setSessions(JSON.parse(savedSessions));
    }
  }, []);

  const categories = ['All', 'Economics', 'Engineering', 'Career', 'Design', 'Science'];
  const filteredSessions = filter === 'All' ? sessions : sessions.filter(s => s.category === filter);

  const sendEmailNotification = (subject: string, body: string) => {
    const recipient = 'siraajjuneja@hotmail.com';
    const mailtoUrl = `mailto:${recipient}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    window.location.href = mailtoUrl;
  };

  const scrollToSection = (id: string) => {
    if (activeView !== 'landing') {
      setActiveView('landing');
      setTimeout(() => {
        const element = document.getElementById(id);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      const element = document.getElementById(id);
      if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const handleSessionSelect = (session: Session) => {
    setSelectedSession(session);
    setModalType('session');
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const email = (e.target as any).email.value;
    const name = authMode === 'signup' ? (e.target as any).name?.value : 'Returning Scholar';

    if (authMode === 'login') {
      const found = userList.find(u => u.email === email);
      if (found) {
        setCurrentUser(found);
        localStorage.setItem('gyaan_active_user', JSON.stringify(found));
        setModalType(null);
        return;
      } else {
        alert("Account not found in the global registry.");
        return;
      }
    }

    const newUser: UserRecord = { email, name, date: new Date().toLocaleDateString(), isFellow: false };
    const updatedList = [...userList, newUser];

    setUserList(updatedList);
    localStorage.setItem('gyaan_users', JSON.stringify(updatedList));
    localStorage.setItem('gyaan_active_user', JSON.stringify(newUser));
    setCurrentUser(newUser);

    setApplyData(prev => ({
      ...prev,
      name: newUser.name,
      email: newUser.email
    }));

    const subject = `Gyaan Forum Registration: ${name}`;
    const body = `A new user has registered for Gyaan Forum.\n\nName: ${name}\nEmail: ${email}\nDate: ${newUser.date}`;
    sendEmailNotification(subject, body);
    setModalType(null);
  };

  const handleLogout = () => {
    localStorage.removeItem('gyaan_active_user');
    setCurrentUser(null);
    setApplyData({ name: '', email: '', expertise: '', background: '' });
  };

  const handleApplyDossier = (e: React.FormEvent) => {
    e.preventDefault();
    const { name, email, expertise, background } = applyData;

    if (!currentUser) {
      alert("Please log in or create an account before submitting your scholarly dossier.");
      setAuthMode('signup');
      setModalType('auth');
      return;
    }

    const newApp: FellowshipApplication = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      name,
      expertise,
      background,
      status: 'PENDING',
      submittedAt: new Date().toLocaleString()
    };

    const updatedApps = [newApp, ...applications];
    setApplications(updatedApps);
    localStorage.setItem('gyaan_applications', JSON.stringify(updatedApps));

    alert("Your scholarly dossier has been recorded in the Fellowship Board. An administrator will review your credentials shortly.");
    setModalType(null);
  };

  // ADMIN ACTIONS
  const adminDeleteUser = (email: string) => {
    if (!confirm("Are you sure? This will remove the scholar from the entire platform.")) return;
    const updated = userList.filter(u => u.email !== email);
    setUserList(updated);
    localStorage.setItem('gyaan_users', JSON.stringify(updated));
  };

  const adminUpdateUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;
    const updated = userList.map(u => u.email === editingUser.email ? editingUser : u);
    setUserList(updated);
    localStorage.setItem('gyaan_users', JSON.stringify(updated));
    setEditingUser(null);
  };

  const adminHandleApplication = (id: string, action: 'APPROVED' | 'REJECTED') => {
    const updatedApps = applications.map(app => {
      if (app.id === id) {
        if (action === 'APPROVED') {
          // Update the user record to be a fellow
          const updatedUsers = userList.map(u => u.email === app.email ? { ...u, isFellow: true, expertise: app.expertise } : u);
          setUserList(updatedUsers);
          localStorage.setItem('gyaan_users', JSON.stringify(updatedUsers));
        }
        return { ...app, status: action };
      }
      return app;
    });
    setApplications(updatedApps);
    localStorage.setItem('gyaan_applications', JSON.stringify(updatedApps));
  };

  const handleAdminCommitSession = (sessionId: string) => {
    const container = adminFormRefs.current[sessionId];
    if (!container) return;

    const title = (container.querySelector('[name="title"]') as HTMLInputElement).value;
    const zoomLink = (container.querySelector('[name="zoomLink"]') as HTMLInputElement).value;
    const category = (container.querySelector('[name="category"]') as HTMLSelectElement).value as Session['category'];
    const description = (container.querySelector('[name="description"]') as HTMLTextAreaElement).value;
    const longDescription = (container.querySelector('[name="longDescription"]') as HTMLTextAreaElement).value;

    const updates = { title, zoomLink, category, description, longDescription };

    const updatedSessions = sessions.map(s => 
      s.id === sessionId ? { ...s, ...updates } : s
    );

    setSessions(updatedSessions);
    localStorage.setItem('gyaan_sessions_registry', JSON.stringify(updatedSessions));

    if (selectedSession && selectedSession.id === sessionId) {
      setSelectedSession({ ...selectedSession, ...updates });
    }

    setConfirmingSessionId(null);
    alert("Masterclass details updated successfully.");
  };

  const handleAdminDeleteSession = (sessionId: string) => {
    if (!confirm("Remove session?")) return;
    const updatedSessions = sessions.filter(s => s.id !== sessionId);
    setSessions(updatedSessions);
    localStorage.setItem('gyaan_sessions_registry', JSON.stringify(updatedSessions));
  };

  const handleAdminCreateSession = (e: React.FormEvent) => {
    e.preventDefault();
    const container = newSessionFormRef.current;
    if (!container) return;

    const title = (container.querySelector('[name="title"]') as HTMLInputElement).value;
    const category = (container.querySelector('[name="category"]') as HTMLSelectElement).value as Session['category'];
    const timeLabel = (container.querySelector('[name="timeLabel"]') as HTMLInputElement).value;
    const status = (container.querySelector('[name="status"]') as HTMLSelectElement).value as Session['status'];
    const mentorName = (container.querySelector('[name="mentorName"]') as HTMLInputElement).value;
    const mentorInst = (container.querySelector('[name="mentorInst"]') as HTMLInputElement).value;
    const mentorTitle = (container.querySelector('[name="mentorTitle"]') as HTMLInputElement).value;
    const mentorBio = (container.querySelector('[name="mentorBio"]') as HTMLTextAreaElement).value;
    const avatarUrl = (container.querySelector('[name="avatarUrl"]') as HTMLInputElement).value || `https://picsum.photos/seed/${Math.random()}/100/100`;
    const description = (container.querySelector('[name="description"]') as HTMLTextAreaElement).value;
    const longDescription = (container.querySelector('[name="longDescription"]') as HTMLTextAreaElement).value;
    const zoomLink = (container.querySelector('[name="zoomLink"]') as HTMLInputElement).value;

    const newSession: Session = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      category,
      timeLabel,
      status,
      mentorName,
      mentorInst,
      mentorTitle,
      mentorBio,
      avatarUrl,
      description,
      longDescription,
      zoomLink,
      relatedSessionIds: []
    };

    const updatedSessions = [newSession, ...sessions];
    setSessions(updatedSessions);
    localStorage.setItem('gyaan_sessions_registry', JSON.stringify(updatedSessions));

    setIsAddingNew(false);
    alert("New masterclass added.");
  };

  const getSessionReviews = (sessionId: string) => reviews.filter(r => r.sessionId === sessionId);

  return (
    <div className="min-h-screen flex flex-col relative bg-[#FDFBF7]">
      <nav className="flex justify-between items-center px-6 md:px-12 py-6 sticky top-0 bg-[#FDFBF7]/90 backdrop-blur-md z-40 border-b border-gray-50">
        <div className="text-2xl font-bold tracking-tighter font-playfair text-[#1A2238] hover:text-[#7FB5B5] cursor-pointer transition-colors" onClick={() => { setActiveView('landing'); window.scrollTo({top: 0, behavior: 'smooth'}); }}>
          GYAAN FORUM
        </div>
        <div className="hidden md:flex space-x-10 text-xs uppercase tracking-widest font-semibold text-gray-500">
          <button onClick={() => scrollToSection('workshops')} className="hover:text-[#1A2238] transition-all hover:tracking-[0.2em]">Sessions</button>
          <button onClick={() => { setActiveView('community'); window.scrollTo({top: 0, behavior: 'smooth'}); }} className={`transition-all ${activeView === 'community' ? 'text-[#1A2238] font-bold border-b-2 border-[#C5A059] pb-1' : 'hover:text-[#1A2238] hover:tracking-[0.2em]'}`}>Community</button>
          <button onClick={() => { setModalType('admin'); setIsAddingNew(false); }} className="text-[#C5A059] font-bold hover:text-[#1A2238] transition flex items-center gap-2 px-3 py-1 bg-[#C5A059]/10 rounded-full group">
            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="group-hover:rotate-90 transition-transform duration-500"><circle cx="12" cy="12" r="3"></circle><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"></path></svg>
            Admin
          </button>
        </div>
        <div className="flex items-center gap-4">
          {currentUser ? (
            <div className="flex items-center gap-4">
              {currentUser.isFellow && <span className="bg-[#C5A059]/10 text-[#C5A059] text-[8px] font-bold px-2 py-0.5 rounded-full uppercase tracking-widest border border-[#C5A059]/20">Fellow</span>}
              <span className="text-[10px] uppercase font-bold text-gray-400">Welcome, {currentUser.name}</span>
              <button onClick={handleLogout} className="text-xs uppercase tracking-widest font-bold text-red-400 hover:text-red-600 transition">Logout</button>
            </div>
          ) : (
            <>
              <button onClick={() => { setAuthMode('login'); setModalType('auth'); }} className="hidden sm:block text-xs uppercase tracking-widest font-bold hover:text-[#7FB5B5] transition">Login</button>
              <button onClick={() => { setAuthMode('signup'); setModalType('auth'); }} className="bg-[#1A2238] text-white px-6 py-2.5 rounded-full text-xs font-bold uppercase tracking-widest hover:bg-[#7FB5B5] transition shadow-md active:scale-95">
                Join Community
              </button>
            </>
          )}
        </div>
      </nav>

      <main className="flex-1">
        {activeView === 'landing' ? (
          <>
            <section className="relative overflow-hidden hero-gradient pt-16 md:pt-24 pb-20 md:pb-32">
              <div className="max-w-6xl mx-auto px-6 text-center relative z-10 animate-scale opacity-0">
                <div className="inline-block py-1 px-4 mb-6 rounded-full bg-[#7FB5B5]/10 border border-[#7FB5B5]/20">
                  <span className="text-[#7FB5B5] font-bold tracking-[0.2em] uppercase text-[10px]">
                    A Collective for Intellectual Growth
                  </span>
                </div>
                <h1 className="text-5xl md:text-8xl mt-4 mb-8 leading-tight font-playfair font-bold text-[#1A2238]">
                  Peer-led learning, <br className="hidden md:block" />
                  <span className="italic font-normal text-[#C5A059]">redefined.</span>
                </h1>
                <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto mb-12 leading-relaxed font-light">
                  Experience curated workshops led by the next generation of academic leaders. 
                  Pure knowledge exchange, designed for those who seek depth over convenience.
                </p>
                <div className="flex flex-col sm:flex-row justify-center gap-6">
                  <button onClick={() => scrollToSection('workshops')} className="bg-[#1A2238] text-white px-10 py-4 rounded-2xl font-bold text-sm tracking-widest uppercase hover:scale-105 transition shadow-xl">
                    Explore Masterclasses
                  </button>
                  <button onClick={() => setModalType('apply')} className="border border-[#1A2238] px-10 py-4 rounded-2xl font-bold text-sm tracking-widest uppercase hover:bg-[#1A2238] hover:text-white transition text-[#1A2238]">
                    Apply to Fellowship
                  </button>
                </div>
              </div>
            </section>

            <section id="workshops" className="bg-white py-24 md:py-32">
              <div className="max-w-6xl mx-auto px-6">
                <div className="flex flex-col md:flex-row justify-between items-end mb-16 gap-8">
                  <div className="text-left w-full md:w-auto animate-in opacity-0">
                    <h2 className="text-4xl md:text-5xl font-playfair font-bold mb-4 text-[#1A2238]">Active Dialogues</h2>
                    <p className="text-gray-400 text-lg">Live learning environments curated for intellectual rigor.</p>
                  </div>
                  <div className="flex flex-wrap gap-2 animate-in opacity-0">
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setFilter(cat)} className={`px-5 py-2.5 rounded-full text-[10px] font-bold uppercase tracking-[0.15em] transition-all duration-300 ${filter === cat ? 'bg-[#1A2238] text-white shadow-xl shadow-[#1A2238]/20 -translate-y-1' : 'bg-gray-50 text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`}>
                        {cat}
                      </button>
                    ))}
                  </div>
                </div>

                <div key={filter} className="grid md:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-12 stagger-container">
                  {filteredSessions.map(session => (
                    <SessionCard 
                      key={session.id} 
                      session={session} 
                      onSelect={handleSessionSelect} 
                      isExpertiseMatch={false}
                      reviews={getSessionReviews(session.id)}
                    />
                  ))}
                  <div onClick={() => { setModalType('admin'); setIsAddingNew(true); }} className="animate-in opacity-0 border-2 border-dashed border-gray-100 rounded-[2.5rem] p-8 flex flex-col items-center justify-center text-center group cursor-pointer hover:border-[#7FB5B5] transition-all bg-gray-50/30 hover:bg-white min-h-[350px]">
                    <div className="w-16 h-16 bg-white shadow-sm rounded-full flex items-center justify-center mb-6 group-hover:bg-[#7FB5B5]/10 group-hover:rotate-90 transition-all duration-500">
                      <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-gray-300 group-hover:text-[#7FB5B5] transition-colors"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
                    </div>
                    <h4 className="font-bold text-[#1A2238] mb-3 text-lg">Propose a Session</h4>
                    <p className="text-xs text-gray-400 max-w-[220px] leading-relaxed font-light">Possess a unique perspective? Access the administrative dashboard to register a new masterclass.</p>
                  </div>
                </div>
              </div>
            </section>
          </>
        ) : (
          <div className="animate-in opacity-0">
            <section className="relative overflow-hidden hero-gradient pt-16 md:pt-24 pb-20 md:pb-32 text-center px-6">
                <h1 className="text-4xl md:text-7xl mb-8 leading-tight font-playfair font-bold text-[#1A2238]">A community built on shared inquiry.</h1>
                <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto mb-12 leading-relaxed font-light">Engage beyond live sessions—through discussion and ongoing peer dialogue.</p>
                <button onClick={() => { if(!currentUser) { setAuthMode('signup'); setModalType('auth'); } }} className="bg-[#1A2238] text-white px-12 py-4 rounded-2xl font-bold text-sm tracking-widest uppercase hover:scale-105 transition shadow-xl active:scale-95">Become Part of the Network</button>
            </section>
          </div>
        )}
      </main>

      {/* Session Modal */}
      <Modal 
        isOpen={modalType === 'session' && !!selectedSession} 
        onClose={() => setModalType(null)} 
        title="Masterclass Specification"
        size="lg"
      >
        {selectedSession && (
          <div className="space-y-12 pb-16">
            <div className="grid md:grid-cols-3 gap-12">
              <div className="md:col-span-2 space-y-10">
                <div className="flex flex-col items-start gap-4">
                  <div className="inline-block py-1 px-3 rounded-full bg-[#7FB5B5]/10 border border-[#7FB5B5]/20">
                    <span className="text-[#7FB5B5] font-bold tracking-widest uppercase text-[10px]">
                      {selectedSession.category} · {selectedSession.timeLabel}
                    </span>
                  </div>
                  <h1 className="text-4xl font-playfair font-bold text-[#1A2238] mb-2 leading-tight">
                    {selectedSession.title}
                  </h1>
                  <p className="text-lg text-gray-500 font-light leading-relaxed">
                    {selectedSession.longDescription}
                  </p>
                </div>

                <div className="bg-[#1A2238] p-8 rounded-[2.5rem] text-white flex flex-col md:flex-row items-center justify-between gap-6 shadow-2xl relative overflow-hidden group">
