                  <button onClick={() => setModalType('apply')} className="border border-[#C5A059]/50 text-[#C5A059] px-14 py-5 rounded-2xl font-bold text-sm tracking-widest uppercase hover:bg-[#C5A059]/10 transition-all active:scale-95">
