                            <td className="px-6 py-4 text-gray-400 text-xs">{user.date}</td>
                            <td className="px-6 py-4">
                              <span className={`text-[9px] font-bold uppercase px-2 py-0.5 rounded-full ${user.isFellow ? 'bg-[#C5A059]/10 text-[#C5A059]' : 'bg-gray-100 text-gray-400'}`}>
                                {user.isFellow ? 'Fellow' : 'Scholar'}
                              </span>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
               </div>
            )}

            {adminTab === 'curriculum' && (
              <div className="space-y-8 animate-in">
                 <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-playfair font-bold">Curriculum Management</h3>
                    <button onClick={() => setIsAddingNew(!isAddingNew)} className="bg-[#1A2238] text-white px-5 py-2.5 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-[#7FB5B5]">Add Session</button>
                 </div>
                 <div className="grid gap-4">
                   {sessions.map(s => (
                     <div key={s.id} className="p-6 border border-gray-100 rounded-[2rem] bg-white flex items-center justify-between group hover:shadow-lg transition-all">
                        <div>
                          <span className="text-[9px] font-bold text-[#7FB5B5] uppercase tracking-widest">{s.category}</span>
                          <h4 className="text-lg font-bold text-[#1A2238] group-hover:text-[#7FB5B5] transition-colors">{s.title}</h4>
                        </div>
                        <button onClick={() => handleAdminDeleteSession(s.id)} className="text-red-400 hover:text-red-600 transition-colors p-2">
                          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                        </button>
                     </div>
                   ))}
                 </div>
              </div>
            )}
          </div>
        </div>
      </Modal>

      <Modal isOpen={modalType === 'auth'} onClose={() => setModalType(null)} title={authMode === 'login' ? "Scholastic Login" : "Join the Collective"} size="sm">
        <form onSubmit={handleAuth} className="space-y-4 animate-in text-[#1A2238]">
          {authMode === 'signup' && <input name="name" type="text" placeholder="Full Name" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none" />}
          <input name="email" type="email" placeholder="Email" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none" />
          <input name="password" type="password" placeholder="Password" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none" />
          <button type="submit" className="w-full bg-[#1A2238] text-white py-4 rounded-xl font-bold text-sm tracking-widest uppercase shadow-lg active:scale-95">
            Authenticate
          </button>
          <p className="text-center text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-4 cursor-pointer hover:text-[#7FB5B5] transition-colors" onClick={() => setAuthMode(authMode === 'login' ? 'signup' : 'login')}>
            {authMode === 'login' ? 'Create New Account' : 'Existing Scholar Login'}
          </p>
        </form>
      </Modal>

      <Modal isOpen={modalType === 'apply'} onClose={() => setModalType(null)} title="Fellowship Dossier">
        <form onSubmit={handleApplyDossier} className="space-y-6 animate-in">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input value={applyData.name} onChange={(e) => setApplyData({...applyData, name: e.target.value})} required type="text" placeholder="Scholar Name" className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none" />
            <input value={applyData.email} onChange={(e) => setApplyData({...applyData, email: e.target.value})} required type="email" placeholder="Institutional ID" className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none" />
          </div>
          <input value={applyData.expertise} onChange={(e) => setApplyData({...applyData, expertise: e.target.value})} required type="text" placeholder="Scholarly Domain" className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none" />
          <textarea value={applyData.background} onChange={(e) => setApplyData({...applyData, background: e.target.value})} required placeholder="Brief academic narrative..." className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm h-44 resize-none outline-none"></textarea>
          <button type="submit" className="w-full bg-[#C5A059] text-white py-5 rounded-2xl font-bold text-xs tracking-widest uppercase hover:shadow-2xl transition-all">
            Submit Scholarly Credentials
          </button>
        </form>
      </Modal>

      <Concierge />
    </div>
  );
}

