            {adminTab === 'fellowship' && (
              <div className="space-y-6 animate-in">
                 <h3 className="text-xl font-playfair font-bold">Review Queue</h3>
                 {applications.length > 0 ? applications.map(app => (
                   <div key={app.id} className="p-8 border border-gray-100 rounded-[2rem] bg-white hover:shadow-xl transition-all">
                      <div className="flex justify-between mb-4">
                        <span className="text-[10px] uppercase font-bold text-[#C5A059]">{app.status}</span>
