                      </div>
                      <h4 className="text-lg font-bold mb-4">{app.name} — {app.expertise}</h4>
                      <p className="text-sm text-gray-500 mb-6 italic">"{app.background}"</p>
                      {app.status === 'PENDING' && (
                        <div className="flex gap-4">
                          <button onClick={() => adminHandleApplication(app.id, 'APPROVED')} className="bg-[#C5A059] text-white px-6 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest">Approve</button>
                          <button onClick={() => adminHandleApplication(app.id, 'REJECTED')} className="border border-red-100 text-red-400 px-6 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest">Decline</button>
