                      <thead className="bg-gray-50 text-[10px] uppercase tracking-widest font-bold text-gray-400 border-b border-gray-100">
                        <tr>
                          <th className="px-6 py-4">Scholar Name</th>
                          <th className="px-6 py-4">Institutional ID</th>
                          <th className="px-6 py-4">Signup Date</th>
                          <th className="px-6 py-4">Status</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {userList.map(user => (
                          <tr key={user.email} className="hover:bg-gray-50/30 transition-colors">
                            <td className="px-6 py-4 font-bold text-[#1A2238]">{user.name}</td>
                            <td className="px-6 py-4 text-gray-500 font-mono text-[11px]">{user.email}</td>
                            <td className="px-6 py-4 text-gray-400 text-xs">{user.date}</td>
                            <td className="px-6 py-4">
                              <span className={`text-[9px] font-bold uppercase px-2 py-0.5 rounded-full ${user.isFellow ? 'bg-[#C5A059]/10 text-[#C5A059]' : 'bg-gray-100 text-gray-400'}`}>
                                {user.isFellow ? 'Fellow' : 'Scholar'}
