  const [modalType, setModalType] = useState<'auth' | 'apply' | 'admin' | 'session' | null>(null);
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');
  const [currentUser, setCurrentUser] = useState<UserRecord | null>(null);
  const [adminMetrics, setAdminMetrics] = useState<AnalyticsSnapshot | null>(null);
  const [activeView, setActiveView] = useState<'landing' | 'community'>('landing');
  const [adminTab, setAdminTab] = useState<'insights' | 'scholars' | 'fellowship' | 'curriculum'>('insights');
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        const data = await getUserData(user.uid);
        setCurrentUser(data);
      } else {
        setCurrentUser(null);
      }
      setIsLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    if (currentUser?.role === 'admin' && modalType === 'admin') {
      getAdminMetrics().then(setAdminMetrics);
    }
  }, [currentUser, modalType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    const email = (e.target as any).email.value;
    const pass = (e.target as any).password.value;
    try {
      if (authMode === 'login') {
        await loginWithEmail(email, pass);
      } else {
        const name = (e.target as any).name.value;
        await signupWithEmail(email, pass, name);
      }
      setModalType(null);
    } catch (err: any) {
      alert(err.message);
    }
  };

  const handleGoogleLogin = async () => {
    try {
      await loginWithGoogle();
      setModalType(null);
    } catch (err: any) {
      alert(err.message);
    }
  };

  const handleLogout = () => signOut(auth);

  if (isLoading) return <div className="h-screen flex items-center justify-center font-playfair text-2xl animate-pulse">Initializing Forum...</div>;

  return (
    <div className="min-h-screen flex flex-col relative bg-[#FDFBF7]">
