          {currentUser?.role === 'admin' && (
            <button onClick={() => setModalType('admin')} className="text-[#C5A059] font-bold text-xs uppercase tracking-widest bg-[#C5A059]/10 px-4 py-2 rounded-full">Admin Panel</button>
          )}
          {currentUser ? (
            <div className="flex items-center gap-4">
              <span className="text-[10px] uppercase font-bold text-gray-400">{currentUser.name} ({currentUser.role})</span>
              <button onClick={handleLogout} className="text-[10px] text-red-400 font-bold uppercase tracking-widest">Logout</button>
            </div>
          ) : (
            <button onClick={() => setModalType('auth')} className="bg-[#1A2238] text-white px-6 py-2.5 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-md">Login / Join</button>
          )}
        </div>
      </nav>

      <main className="flex-1">
        {activeView === 'landing' ? (
          <section className="py-20 px-6 max-w-6xl mx-auto">
            <h1 className="text-6xl md:text-8xl font-playfair font-bold text-[#1A2238] mb-12 animate-in">The Scholar's Network.</h1>
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
              {sessions.map(s => (
                <SessionCard key={s.id} session={s} reviews={[]} onSelect={() => setSelectedSession(s)} onJoin={async (id) => currentUser && await trackAttendance(currentUser.uid, id)} />
              ))}
            </div>
          </section>
        ) : (
          <div className="p-12 text-center animate-in">
            <h2 className="text-4xl font-playfair font-bold mb-4">Community Discussions</h2>
            <p className="text-gray-500">Feature migration in progress to secure cloud backend.</p>
