  );
};

function App() {
  const [sessions, setSessions] = useState<Session[]>(INITIAL_SESSIONS);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [filter, setFilter] = useState<string>('All');
  const [modalType, setModalType] = useState<'auth' | 'apply' | 'admin' | 'session' | null>(null);
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');
  const [currentUser, setCurrentUser] = useState<UserRecord | null>(null);
  const [userList, setUserList] = useState<UserRecord[]>([]);
  const [applications, setApplications] = useState<FellowshipApplication[]>([]);
  const [activeView, setActiveView] = useState<'landing' | 'community'>('landing');
  const [adminTab, setAdminTab] = useState<'insights' | 'scholars' | 'fellowship' | 'curriculum'>('insights');
  const [linkingSessionId, setLinkingSessionId] = useState<string | null>(null);
  const [isAddingNew, setIsAddingNew] = useState(false);

  // New Session Form State
  const [newSession, setNewSession] = useState<Partial<Session>>({
    title: '',
    category: 'Economics',
    timeLabel: '',
    mentorName: '',
    mentorInst: '',
    description: '',
    longDescription: '',
    zoomLink: '',
    status: 'UPCOMING'
  });

  useEffect(() => {
    const savedUsers = localStorage.getItem('gyaan_users');
    if (savedUsers) setUserList(JSON.parse(savedUsers));

    const savedApps = localStorage.getItem('gyaan_applications');
    if (savedApps) setApplications(JSON.parse(savedApps));

    const activeSession = localStorage.getItem('gyaan_active_user');
    if (activeSession) {
      const user = JSON.parse(activeSession);
      setCurrentUser({ ...user, isAdmin: user.email === ADMIN_EMAIL });
    }

    const savedReviews = localStorage.getItem('gyaan_reviews');
    if (savedReviews) setReviews(JSON.parse(savedReviews));

    const savedSessions = localStorage.getItem('gyaan_sessions_registry');
    if (savedSessions) setSessions(JSON.parse(savedSessions));
  }, []);

  const categories = ['All', 'Economics', 'Engineering', 'Career', 'Design', 'Science'];
  const filteredSessions = filter === 'All' ? sessions : sessions.filter(s => s.category === filter);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const email = (e.target as any).email.value;
    const name = authMode === 'signup' ? (e.target as any).name?.value : 'Returning Scholar';

    if (authMode === 'login') {
      const found = userList.find(u => u.email === email);
      if (found) {
        const userWithAdmin = { ...found, isAdmin: found.email === ADMIN_EMAIL };
        setCurrentUser(userWithAdmin);
        localStorage.setItem('gyaan_active_user', JSON.stringify(userWithAdmin));
        setModalType(null);
        return;
      } else {
        alert("Account not found.");
        return;
      }
    }

    const newUser: UserRecord = { email, name, date: new Date().toLocaleDateString(), isFellow: false };
    const updatedList = [...userList, newUser];
    setUserList(updatedList);
    localStorage.setItem('gyaan_users', JSON.stringify(updatedList));
    setCurrentUser({ ...newUser, isAdmin: email === ADMIN_EMAIL });
    localStorage.setItem('gyaan_active_user', JSON.stringify(newUser));
    setModalType(null);
  };

  const handleLogout = () => {
    localStorage.removeItem('gyaan_active_user');
    setCurrentUser(null);
  };

  const handleAdminAddSession = (e: React.FormEvent) => {
    e.preventDefault();
    const sessionToAdd: Session = {
      ...newSession as Session,
      id: Math.random().toString(36).substr(2, 9),
      avatarUrl: `https://picsum.photos/seed/${newSession.mentorName}/100/100`,
      mentorBio: 'Mentor bio placeholder for administrative entry.',
      mentorTitle: 'Guest Mentor',
    };
    const updated = [sessionToAdd, ...sessions];
    setSessions(updated);
    localStorage.setItem('gyaan_sessions_registry', JSON.stringify(updated));
    setIsAddingNew(false);
    setNewSession({ title: '', category: 'Economics', timeLabel: '', mentorName: '', mentorInst: '', description: '', longDescription: '', zoomLink: '', status: 'UPCOMING' });
  };

  const handleAdminDeleteSession = (sessionId: string) => {
    if (!confirm("Remove session?")) return;
    const updated = sessions.filter(s => s.id !== sessionId);
    setSessions(updated);
    localStorage.setItem('gyaan_sessions_registry', JSON.stringify(updated));
  };

  const handleToggleScholarLink = (sessionId: string, scholarEmail: string) => {
    const updated = sessions.map(s => {
      if (s.id === sessionId) {
        const current = s.linkedScholarEmails || [];
        const isLinked = current.includes(scholarEmail);
        return { ...s, linkedScholarEmails: isLinked ? current.filter(e => e !== scholarEmail) : [...current, scholarEmail] };
      }
      return s;
    });
    setSessions(updated);
    localStorage.setItem('gyaan_sessions_registry', JSON.stringify(updated));
  };

  const adminHandleApplication = (id: string, action: 'APPROVED' | 'REJECTED') => {
    const updatedApps = applications.map(app => {
      if (app.id === id) {
        if (action === 'APPROVED') {
          const updatedUsers = userList.map(u => u.email === app.email ? { ...u, isFellow: true } : u);
          setUserList(updatedUsers);
          localStorage.setItem('gyaan_users', JSON.stringify(updatedUsers));
        }
        return { ...app, status: action };
      }
      return app;
    });
    setApplications(updatedApps);
    localStorage.setItem('gyaan_applications', JSON.stringify(updatedApps));
  };

  return (
    <div className="min-h-screen flex flex-col relative bg-[#FDFBF7]">
      <nav className="flex justify-between items-center px-6 md:px-12 py-6 sticky top-0 bg-[#FDFBF7]/90 backdrop-blur-md z-40 border-b border-gray-50">
        <div className="text-2xl font-bold tracking-tighter font-playfair text-[#1A2238] cursor-pointer" onClick={() => setActiveView('landing')}>GYAAN FORUM</div>
        <div className="hidden md:flex space-x-10 text-xs uppercase tracking-widest font-semibold text-gray-500">
          <button onClick={() => setActiveView('landing')} className={activeView === 'landing' ? 'text-[#1A2238]' : ''}>Landing</button>
          <button onClick={() => setActiveView('community')} className={activeView === 'community' ? 'text-[#1A2238]' : ''}>Community</button>
          {currentUser?.isAdmin && (
            <button onClick={() => setModalType('admin')} className="text-[#C5A059] font-bold bg-[#C5A059]/10 px-4 py-1.5 rounded-full">Admin Dashboard</button>
          )}
        </div>
        <div>
          {currentUser ? (
            <div className="flex items-center gap-4">
              <span className="text-[10px] uppercase font-bold text-gray-400">Hi, {currentUser.name}</span>
              <button onClick={handleLogout} className="text-xs font-bold text-red-400">Logout</button>
            </div>
          ) : (
            <button onClick={() => setModalType('auth')} className="bg-[#1A2238] text-white px-6 py-2.5 rounded-full text-xs font-bold uppercase">Join Community</button>
          )}
        </div>
      </nav>

      <main className="flex-1">
        {activeView === 'landing' ? (
          <section className="max-w-6xl mx-auto px-6 py-20">
             <h1 className="text-5xl md:text-8xl font-playfair font-bold text-[#1A2238] mb-12">The Peer <span className="italic font-normal text-[#C5A059]">Curriculum</span></h1>
             <div className="flex flex-wrap gap-2 mb-12">
                {categories.map(cat => (
                  <button key={cat} onClick={() => setFilter(cat)} className={`px-5 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest transition ${filter === cat ? 'bg-[#1A2238] text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>{cat}</button>
                ))}
             </div>
             <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8 stagger-container">
               {filteredSessions.map(s => <SessionCard key={s.id} session={s} onSelect={setSelectedSession} reviews={[]} />)}
             </div>
          </section>
        ) : (
          <div className="p-20 text-center animate-in"><h2 className="text-4xl font-playfair font-bold">Community Dialogue Hub</h2><p className="text-gray-400 mt-4">Peer-to-peer discussion boards loading...</p></div>
        )}
      </main>

      {/* ADMIN MODAL RESTORATION */}
      <Modal isOpen={modalType === 'admin'} onClose={() => { setModalType(null); setAdminTab('insights'); }} title="Administrator Intelligence Board" size="xl">
        <div className="flex flex-col md:flex-row gap-8 min-h-[600px] text-[#1A2238]">
          <div className="w-full md:w-64 space-y-2 border-r border-gray-50 pr-6">
            {['insights', 'scholars', 'fellowship', 'curriculum'].map(tab => (
              <button key={tab} onClick={() => setAdminTab(tab as any)} className={`w-full text-left px-4 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition ${adminTab === tab ? 'bg-[#1A2238] text-white shadow-lg' : 'text-gray-400 hover:bg-gray-50'}`}>
                {tab === 'scholars' ? 'Scholars Registry' : tab.charAt(0).toUpperCase() + tab.slice(1)}
              </button>
            ))}
          </div>

          <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
            {adminTab === 'insights' && (
              <div className="grid grid-cols-2 gap-6 animate-in">
                {[
                  { label: 'Global Scholars', val: userList.length },
                  { label: 'Approved Fellows', val: userList.filter(u => u.isFellow).length },
                  { label: 'Active Dossiers', val: applications.filter(a => a.status === 'PENDING').length },
                  { label: 'Live Sessions', val: sessions.length }
                ].map((stat, i) => (
                  <div key={i} className="p-8 bg-gray-50 rounded-[2rem] border border-gray-100">
                    <p className="text-[10px] uppercase font-bold text-gray-400 tracking-widest mb-2">{stat.label}</p>
                    <p className="text-4xl font-playfair font-bold">{stat.val}</p>
                  </div>
                ))}
              </div>
            )}

            {adminTab === 'scholars' && (
              <div className="animate-in space-y-6">
                <h3 className="text-xl font-playfair font-bold">Registry Table</h3>
                <div className="overflow-hidden rounded-3xl border border-gray-100">
                  <table className="w-full text-left text-sm">
                    <thead className="bg-gray-50 text-[10px] uppercase font-bold text-gray-400 border-b border-gray-100">
                      <tr><th className="px-6 py-4">Name</th><th className="px-6 py-4">ID</th><th className="px-6 py-4">Status</th></tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {userList.map(u => (
                        <tr key={u.email}><td className="px-6 py-4 font-bold">{u.name}</td><td className="px-6 py-4 text-gray-400 font-mono text-xs">{u.email}</td><td className="px-6 py-4"><span className={`text-[9px] font-bold px-2 py-0.5 rounded-full ${u.isFellow ? 'bg-[#C5A059]/10 text-[#C5A059]' : 'bg-gray-100 text-gray-400'}`}>{u.isFellow ? 'FELLOW' : 'SCHOLAR'}</span></td></tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {adminTab === 'fellowship' && (
              <div className="animate-in space-y-6">
                <h3 className="text-xl font-playfair font-bold">Fellowship Approval Queue</h3>
                {applications.filter(a => a.status === 'PENDING').length > 0 ? (
                  applications.filter(a => a.status === 'PENDING').map(app => (
                    <div key={app.id} className="p-6 border border-gray-100 rounded-[2rem] space-y-4">
                      <div className="flex justify-between items-start">
                        <div><p className="font-bold">{app.name}</p><p className="text-xs text-[#7FB5B5]">{app.expertise}</p></div>
                        <span className="text-[10px] text-gray-400">{app.submittedAt}</span>
                      </div>
                      <p className="text-sm text-gray-500 italic leading-relaxed">"{app.background}"</p>
                      <div className="flex gap-2">
                        <button onClick={() => adminHandleApplication(app.id, 'APPROVED')} className="bg-[#1A2238] text-white px-6 py-2 rounded-xl text-[10px] font-bold uppercase">Approve</button>
                        <button onClick={() => adminHandleApplication(app.id, 'REJECTED')} className="bg-red-50 text-red-400 px-6 py-2 rounded-xl text-[10px] font-bold uppercase">Decline</button>
                      </div>
                    </div>
                  ))
                ) : <p className="text-gray-400 text-sm italic py-10 text-center">No dossiers pending review.</p>}
              </div>
            )}

            {adminTab === 'curriculum' && (
              <div className="animate-in space-y-8">
                <div className="flex justify-between items-center">
                  <h3 className="text-xl font-playfair font-bold">Curriculum Control</h3>
                  <button onClick={() => setIsAddingNew(!isAddingNew)} className="bg-[#1A2238] text-white px-5 py-2 rounded-xl text-[10px] font-bold uppercase">{isAddingNew ? 'Cancel' : 'Add Session'}</button>
                </div>

                {isAddingNew && (
                  <form onSubmit={handleAdminAddSession} className="bg-gray-50 p-8 rounded-[2rem] border border-gray-100 grid grid-cols-2 gap-4 animate-scale">
                    <input value={newSession.title} onChange={e => setNewSession({...newSession, title: e.target.value})} placeholder="Title" required className="col-span-2 bg-white border border-gray-100 rounded-xl px-4 py-3 text-sm" />
                    <select value={newSession.category} onChange={e => setNewSession({...newSession, category: e.target.value as any})} className="bg-white border border-gray-100 rounded-xl px-4 py-3 text-sm">
                      {categories.filter(c => c !== 'All').map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                    <input value={newSession.timeLabel} onChange={e => setNewSession({...newSession, timeLabel: e.target.value})} placeholder="Time (e.g. LIVE @ 6 PM)" required className="bg-white border border-gray-100 rounded-xl px-4 py-3 text-sm" />
                    <input value={newSession.mentorName} onChange={e => setNewSession({...newSession, mentorName: e.target.value})} placeholder="Mentor Name" required className="bg-white border border-gray-100 rounded-xl px-4 py-3 text-sm" />
                    <input value={newSession.mentorInst} onChange={e => setNewSession({...newSession, mentorInst: e.target.value})} placeholder="Institution" required className="bg-white border border-gray-100 rounded-xl px-4 py-3 text-sm" />
                    <textarea value={newSession.description} onChange={e => setNewSession({...newSession, description: e.target.value})} placeholder="Brief Description" className="col-span-2 bg-white border border-gray-100 rounded-xl px-4 py-3 text-sm h-24" />
                    <button type="submit" className="col-span-2 bg-[#7FB5B5] text-[#1A2238] py-4 rounded-xl font-bold uppercase tracking-widest text-xs">Publish to Curriculum</button>
                  </form>
                )}

                <div className="space-y-4">
                  {sessions.map(s => (
                    <div key={s.id} className="p-6 bg-white border border-gray-100 rounded-[2rem] group">
                      <div className="flex justify-between items-center">
                        <div><p className="font-bold group-hover:text-[#7FB5B5] transition">{s.title}</p><p className="text-[10px] text-gray-400 uppercase tracking-widest">{s.category}</p></div>
                        <div className="flex gap-2">
                          <button onClick={() => setLinkingSessionId(linkingSessionId === s.id ? null : s.id)} className={`p-2 rounded-lg ${linkingSessionId === s.id ? 'bg-[#C5A059] text-white' : 'bg-gray-50 text-gray-400 hover:text-[#C5A059]'}`}><svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="8.5" cy="7" r="4"></circle><line x1="20" y1="8" x2="20" y2="14"></line><line x1="23" y1="11" x2="17" y2="11"></line></svg></button>
                          <button onClick={() => handleAdminDeleteSession(s.id)} className="p-2 bg-gray-50 text-red-300 hover:text-red-500 rounded-lg"><svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg></button>
                        </div>
                      </div>
                      {linkingSessionId === s.id && (
                        <div className="mt-4 pt-4 border-t border-gray-50 grid grid-cols-2 gap-2 max-h-40 overflow-y-auto">
                          {userList.map(user => (
                            <button key={user.email} onClick={() => handleToggleScholarLink(s.id, user.email)} className={`text-[10px] text-left p-2 rounded-lg border transition ${s.linkedScholarEmails?.includes(user.email) ? 'bg-[#C5A059]/10 border-[#C5A059] text-[#C5A059]' : 'bg-white border-gray-50 text-gray-400'}`}>
                              {user.name} <span className="opacity-50 font-mono">({user.email})</span>
                            </button>
                          ))}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </Modal>

      <Modal isOpen={modalType === 'auth'} onClose={() => setModalType(null)} title={authMode === 'login' ? 'Scholar Login' : 'Join Collective'} size="sm">
        <form onSubmit={handleAuth} className="space-y-4">
          {authMode === 'signup' && <input name="name" placeholder="Name" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm" />}
          <input name="email" type="email" placeholder="Email" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm" />
          <input name="password" type="password" placeholder="Password" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm" />
          <button type="submit" className="w-full bg-[#1A2238] text-white py-4 rounded-xl font-bold uppercase text-xs">Authenticate</button>
          <p onClick={() => setAuthMode(authMode === 'login' ? 'signup' : 'login')} className="text-center text-[10px] text-gray-400 uppercase font-bold cursor-pointer hover:text-[#7FB5B5]">{authMode === 'login' ? 'Create Account' : 'Login Instead'}</p>
        </form>
      </Modal>

      <Concierge />
    </div>
  );
}

export default App;

export interface Review {
  id: string;
  sessionId: string;
  userName: string;
  rating: number;
  comment: string;
  date: string;
}

export interface Session {
  id: string;
  title: string;
  category: 'Economics' | 'Engineering' | 'Career' | 'Design' | 'Science';
  timeLabel: string;
  status: 'LIVE' | 'UPCOMING' | 'NOW';
  mentorName: string;
  mentorInst: string;
  mentorTitle: string;
  mentorBio: string;
  avatarUrl: string;
  description: string;
  longDescription: string;
  zoomLink?: string;
  relatedSessionIds?: string[];
  linkedScholarEmails?: string[];
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

export interface UserRecord {
  email: string;
  name: string;
  date: string;
  expertise?: string;
  isFellow?: boolean;
  isAdmin?: boolean;
}

export interface FellowshipApplication {
  id: string;
  email: string;
  name: string;
  expertise: string;
  background: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  submittedAt: string;
}

import React, { useState, useEffect } from 'react';
import { SessionCard } from './components/SessionCard';
import { Concierge } from './components/Concierge';
import { INITIAL_SESSIONS } from './constants';
import { Session, Review, UserRecord, FellowshipApplication } from './types';

const ADMIN_EMAIL = 'admin@gyaan.one';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, size = 'md' }) => {
  if (!isOpen) return null;
  const sizeClasses = { sm: 'max-w-md', md: 'max-w-2xl', lg: 'max-w-4xl', xl: 'max-w-6xl' };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#1A2238]/60 backdrop-blur-sm" onClick={onClose}></div>
      <div className={`relative bg-white w-full ${sizeClasses[size]} rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale max-h-[90vh] flex flex-col`}>
        <div className="p-8 pb-4 flex justify-between items-center sticky top-0 bg-white z-10 border-b border-gray-50">
          <h2 className="text-2xl font-playfair font-bold text-[#1A2238]">{title}</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-2 hover:bg-gray-50 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>
        <div className="overflow-y-auto flex-1 p-8 pt-6">
          {children}
        </div>
      </div>
    </div>
  );
};

function App() {
  const [sessions, setSessions] = useState<Session[]>(INITIAL_SESSIONS);
  const [filter, setFilter] = useState<string>('All');
  const [modalType, setModalType] = useState<'auth' | 'apply' | 'session' | null>(null);
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');
  const [currentUser, setCurrentUser] = useState<UserRecord | null>(null);
  const [userList, setUserList] = useState<UserRecord[]>([]);
  const [activeView, setActiveView] = useState<'landing' | 'community'>('landing');

  useEffect(() => {
    const savedUsers = localStorage.getItem('gyaan_users');
    if (savedUsers) setUserList(JSON.parse(savedUsers));

    const activeSession = localStorage.getItem('gyaan_active_user');
    if (activeSession) {
      const user = JSON.parse(activeSession);
      setCurrentUser({ ...user, isAdmin: user.email === ADMIN_EMAIL });
    }
  }, []);

  const categories = ['All', 'Economics', 'Engineering', 'Career', 'Design', 'Science'];
  const filteredSessions = filter === 'All' ? sessions : sessions.filter(s => s.category === filter);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const email = (e.target as any).email.value;
    const name = authMode === 'signup' ? (e.target as any).name?.value : 'Returning Scholar';

    if (authMode === 'login') {
      const found = userList.find(u => u.email === email);
      if (found) {
        const userWithAdmin = { ...found, isAdmin: found.email === ADMIN_EMAIL };
        setCurrentUser(userWithAdmin);
        localStorage.setItem('gyaan_active_user', JSON.stringify(userWithAdmin));
        setModalType(null);
        return;
      } else {
        alert("Account not found.");
        return;
      }
    }

    const newUser: UserRecord = { email, name, date: new Date().toLocaleDateString(), isFellow: false };
    const updatedList = [...userList, newUser];
    setUserList(updatedList);
    localStorage.setItem('gyaan_users', JSON.stringify(updatedList));
    setCurrentUser({ ...newUser, isAdmin: email === ADMIN_EMAIL });
    localStorage.setItem('gyaan_active_user', JSON.stringify(newUser));
    setModalType(null);
  };

  const handleLogout = () => {
    localStorage.removeItem('gyaan_active_user');
    setCurrentUser(null);
  };

  return (
    <div className="min-h-screen flex flex-col relative bg-[#FDFBF7]">
      <nav className="flex justify-between items-center px-6 md:px-12 py-6 sticky top-0 bg-[#FDFBF7]/90 backdrop-blur-md z-40 border-b border-gray-50">
        <div className="text-2xl font-bold tracking-tighter font-playfair text-[#1A2238] cursor-pointer" onClick={() => setActiveView('landing')}>GYAAN FORUM</div>
        <div className="hidden md:flex space-x-10 text-xs uppercase tracking-widest font-semibold text-gray-500">
          <button onClick={() => setActiveView('landing')} className={activeView === 'landing' ? 'text-[#1A2238]' : ''}>Landing</button>
          <button onClick={() => setActiveView('community')} className={activeView === 'community' ? 'text-[#1A2238]' : ''}>Community</button>
        </div>
        <div>
          {currentUser ? (
            <div className="flex items-center gap-4">
              <span className="text-[10px] uppercase font-bold text-gray-400">Hi, {currentUser.name}</span>
              <button onClick={handleLogout} className="text-xs font-bold text-red-400">Logout</button>
            </div>
          ) : (
            <button onClick={() => setModalType('auth')} className="bg-[#1A2238] text-white px-6 py-2.5 rounded-full text-xs font-bold uppercase">Join Community</button>
          )}
        </div>
      </nav>

      <main className="flex-1">
        {activeView === 'landing' ? (
          <section className="max-w-6xl mx-auto px-6 py-20">
             <h1 className="text-5xl md:text-8xl font-playfair font-bold text-[#1A2238] mb-12">The Peer <span className="italic font-normal text-[#C5A059]">Curriculum</span></h1>
             <div className="flex flex-wrap gap-2 mb-12">
                {categories.map(cat => (
                  <button key={cat} onClick={() => setFilter(cat)} className={`px-5 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest transition ${filter === cat ? 'bg-[#1A2238] text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>{cat}</button>
                ))}
             </div>
             <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8 stagger-container">
               {filteredSessions.map(s => <SessionCard key={s.id} session={s} onSelect={setSelectedSession} reviews={[]} />)}
             </div>
          </section>
        ) : (
          <div className="p-20 text-center animate-in"><h2 className="text-4xl font-playfair font-bold">Community Dialogue Hub</h2><p className="text-gray-400 mt-4">Peer-to-peer discussion boards loading...</p></div>
        )}
      </main>

      <Modal isOpen={modalType === 'auth'} onClose={() => setModalType(null)} title={authMode === 'login' ? 'Scholar Login' : 'Join Collective'} size="sm">
        <form onSubmit={handleAuth} className="space-y-4">
          {authMode === 'signup' && <input name="name" placeholder="Name" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm" />}
          <input name="email" type="email" placeholder="Email" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm" />
          <input name="password" type="password" placeholder="Password" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm" />
          <button type="submit" className="w-full bg-[#1A2238] text-white py-4 rounded-xl font-bold uppercase text-xs">Authenticate</button>
          <p onClick={() => setAuthMode(authMode === 'login' ? 'signup' : 'login')} className="text-center text-[10px] text-gray-400 uppercase font-bold cursor-pointer hover:text-[#7FB5B5]">{authMode === 'login' ? 'Create Account' : 'Login Instead'}</p>
        </form>
      </Modal>

      <Concierge />
    </div>
  );
}

export default App;

