      {/* ADMIN DASHBOARD */}
      <Modal isOpen={modalType === 'admin'} onClose={() => { setModalType(null); setAdminTab('insights'); setEditingSessionId(null); setEditingUserId(null); }} title="Administrator Intelligence Board" size="xl">
