                </div>
              </div>
            )}

            {adminTab === 'fellowship' && (
              <div className="animate-in space-y-6">
                <h3 className="text-xl font-playfair font-bold">Fellowship Approval Queue</h3>
                {applications.filter(a => a.status === 'PENDING').length > 0 ? (
                  applications.filter(a => a.status === 'PENDING').map(app => (
                    <div key={app.id} className="p-6 border border-gray-100 rounded-[2rem] space-y-4">
                      <div><p className="font-bold">{app.name}</p><p className="text-xs text-[#7FB5B5]">{app.expertise}</p></div>
                      <p className="text-sm text-gray-500 italic">"{app.background}"</p>
                      <div className="flex gap-2">
                        <button onClick={() => adminHandleApplication(app.id, 'APPROVED')} className="bg-[#1A2238] text-white px-6 py-2 rounded-xl text-[10px] font-bold uppercase">Approve</button>
