          </div>
        </div>
      </Modal>

      {/* AUTH MODAL ENHANCED */}
      <Modal isOpen={modalType === 'auth'} onClose={() => setModalType(null)} title={authMode === 'login' ? 'Scholar Login' : 'Join Collective'} size="sm">
        <div className="space-y-6">
          <button 
            onClick={handleGoogleAuth}
            className="w-full flex items-center justify-center gap-3 bg-white border border-gray-100 py-3.5 rounded-xl shadow-sm hover:shadow-md hover:bg-gray-50 transition-all active:scale-95"
          >
            <svg width="20" height="20" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
              <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
              <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/>
              <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
            </svg>
            <span className="text-sm font-bold text-[#1A2238]">Continue with Google</span>
          </button>

          <div className="flex items-center gap-4 py-2">
            <div className="h-px bg-gray-100 flex-1"></div>
            <span className="text-[10px] font-bold text-gray-300 uppercase tracking-widest">or email</span>
            <div className="h-px bg-gray-100 flex-1"></div>
          </div>

          <form onSubmit={handleAuth} className="space-y-4">
            {authMode === 'signup' && (
              <div className="space-y-1">
                <label className="text-[9px] font-bold text-gray-400 uppercase tracking-wider ml-1">Full Name</label>
                <input name="name" placeholder="E.g., Leonardo da Vinci" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none focus:ring-1 focus:ring-[#7FB5B5] transition-all" />
              </div>
            )}
            <div className="space-y-1">
              <label className="text-[9px] font-bold text-gray-400 uppercase tracking-wider ml-1">Institutional ID / Email</label>
              <input name="email" type="email" placeholder="scholar@gyaan.one" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none focus:ring-1 focus:ring-[#7FB5B5] transition-all" />
            </div>
            <div className="space-y-1">
              <label className="text-[9px] font-bold text-gray-400 uppercase tracking-wider ml-1">Secure Password</label>
              <input name="password" type="password" placeholder="••••••••" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none focus:ring-1 focus:ring-[#7FB5B5] transition-all" />
            </div>
            <button type="submit" className="w-full bg-[#1A2238] text-white py-4 rounded-xl font-bold uppercase text-xs hover:bg-[#7FB5B5] transition shadow-lg active:scale-95 mt-2">
              {authMode === 'login' ? 'Authenticate' : 'Initialize Profile'}
            </button>
            <p onClick={() => setAuthMode(authMode === 'login' ? 'signup' : 'login')} className="text-center text-[10px] text-gray-400 uppercase font-bold cursor-pointer hover:text-[#7FB5B5] transition mt-4">
              {authMode === 'login' ? 'No dossier? Initialize New Account' : 'Existing Scholar? Direct Login'}
            </p>
          </form>
        </div>
      </Modal>

      <Modal isOpen={modalType === 'apply'} onClose={() => setModalType(null)} title="Fellowship Dossier">
        <form onSubmit={(e) => { e.preventDefault(); alert("Fellowship application submitted."); setModalType(null); }} className="space-y-4">
          <input placeholder="Domain of Expertise" required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm outline-none" />
          <textarea placeholder="Academic Narrative..." required className="w-full bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-sm h-32 outline-none resize-none" />
          <button type="submit" className="w-full bg-[#C5A059] text-white py-4 rounded-xl font-bold uppercase text-xs active:scale-95 shadow-xl">Submit for Review</button>
        </form>
      </Modal>

      <Concierge />
    </div>
  );
}

